// Localized long-form content for one tutorial. Generated from validated
// per-locale translation JSONs; en renders from the Markdown source.
export const entry: Partial<Record<string, LocalizedTutorialContent>> = {
  "zh": {
    title: "Open Design：免费开源的 Claude Design 替代品",
    summary: "基于 Code A Program 的演示：在 Open Design 里搭建一个完整的 AI 写作工具落地页——挑选一个编码 agent（哪怕是免费的），用提示词生成设计，再用画布上的编辑打磨，最后导出或一键部署到 Vercel 或 Cloudflare。",
    bodyHtml: "<p>Open Design 把一个想法变成原型、网站、幻灯片，甚至 HTML 视频——全部在你自己的机器上本地运行。在这个演示里，Code A Program 安装了桌面应用、接入了一个编码 agent，为一个名为 <em>Draft</em> 的 AI 写作工具搭建了一个精致的落地页，然后无需离开工作区就完成了打磨与部署。可观看 <a href=\"https://www.youtube.com/watch?v=2AdKzkQyKkg\">Code A Program 的完整视频</a>，或继续阅读下方的图文版。</p>\n<p><img src=\"/tutorials/open-design-free-open-source-alternative-code-a-program/01-workspace.webp\" alt=\"本地运行的 Open Design 工作区。\">\n<em>在本地运行的 Open Design：一个由你完全掌控的开源、agent 原生设计工作区——不被绑定在单一模型上。</em></p>\n<h2 id=\"what-is-open-design\">什么是 Open Design？</h2>\n<p>Open Design 是一个开源、本地优先的设计平台——Claude Design 和 Figma 的免费替代品。它不把你绑定在某个模型厂商上，而是<strong>运行在你已经使用的编码 agent 之上</strong>，所以你可以自带 agent、自带 key。</p>\n<ul>\n<li><strong>开源，Apache-2.0</strong>——读每一行代码、自托管，或者直接下载桌面应用。</li>\n<li><strong>本地运行</strong>——项目就存在你机器上你自己的文件夹里，而不是别人的云端。</li>\n<li><strong>自带 agent</strong>——支持 21+ 编码 agent，包括 Claude Code、Codex、Cursor、Gemini、OpenCode 等等；由你决定用哪个 CLI 来驱动生成。</li>\n<li><strong>不止于原型</strong>——网站、原型、幻灯片、图像生成，甚至 HTML 视频，全都在一个工作区里完成。</li>\n<li><strong>开箱即用</strong>——内置 129 套设计系统和 460+ 插件，让你永远不必从一张白纸开始。</li>\n</ul>\n<p>如果你用过 Claude Design，会立刻感到熟悉——Open Design 保留了同样从容的体验，然后在上面加上你自己选择的模型。</p>\n<h2 id=\"step-1--choose-your-agent-and-model\">第 1 步 —— 选择你的 agent 和模型</h2>\n<p>从 <a href=\"https://open-design.ai/\">open-design.ai</a> 下载桌面应用，安装它，回答几个简短的引导问题。这就把你带进了主聊天界面。</p>\n<p>在<strong>右上角</strong>选择你的 AI agent 提供方。对于本地 CLI 提供方，你可以选择 Claude Code、Codex CLI、Gemini CLI（它有免费额度）、OpenCode 等。在演示中，Code A Program 使用 <strong>OpenCode 搭配 GLM 5.2 模型</strong>，因为它在前端工作上一直表现不错——但关键在于灵活性：你不会被锁定在某一个模型或平台上。</p>\n<h2 id=\"step-2--write-your-prompt\">第 2 步 —— 写你的提示词</h2>\n<p>聊天框有一个<strong>附加文件</strong>选项用于参考材料，还有一个<strong>插件</strong>区。Open Design 内置 460+ 插件，涵盖构建与测试助手、3D 模型、移动端和桌面端设备外框等——所以当你需要 3D 元素或设备外壳时，加个插件就行，而不必和提示词较劲。</p>\n<p><img src=\"/tutorials/open-design-free-open-source-alternative-code-a-program/plugin-library.webp\" alt=\"Open Design 插件库。\">\n<em>插件库：460+ 插件，涵盖构建、测试、3D 模型、设备外框等等——按你的设计所需添加。</em></p>\n<p>现在粘贴一段需求。演示里的提示词要求做一个<strong>面向名为 Draft 的 AI 写作助手的精致落地页</strong>，采用克制的石板黑、象牙白和电光橙配色，一个带实时文字生成动画的醒目编辑风英雄区、一个可交互的写作画布、一个三步工作流、一个成果展示区、一个双档定价表、一个 FAQ，以及一个有力的最终行动号召——同时明确避免卡片、渐变、玻璃拟态和千篇一律的机器人图像。</p>\n<p>还有一个值得知道的手段：你可以基于来自 Apple、Airbnb、BMW、IBM 或 Spotify 等品牌的<strong>流行设计系统</strong>来做设计。Code A Program 在这次演示里跳过了它，但当你想匹配某种特定观感时，它就在那里。</p>\n<h2 id=\"step-3--watch-it-build-and-self-check\">第 3 步 —— 看它构建并自我检查</h2>\n<p>提交提示词，Open Design 就开始准备项目。大约一分钟后，它可能会问几个<strong>追问问题</strong>——回答它们能得到更好的结果，或者点<strong>全部跳过</strong>让它继续。</p>\n<p>在演示中，落地页本身大约在<strong>六分钟</strong>内完成。之后 Open Design 会把剩下的时间花在跑<strong>自我检查</strong>上——校验结构、审视布局、检查动画，并在标记构建完成前修掉一些小问题。完成后，点击<strong>演示图标</strong>即可在新标签页打开这个网站。</p>\n<p><img src=\"/tutorials/open-design-free-open-source-alternative-code-a-program/generated-prototype.webp\" alt=\"在 Open Design 中预览的一个生成好的落地页。\">\n<em>生成的结果：一个带实时打字动画的编辑风英雄区、工作流、成果、定价、FAQ 和页脚——在平板和手机上都自适应。</em></p>\n<p>结果包含一个带 AI 打字动画的英雄区、流畅的滚动效果、一个可交互的编辑器区、一条工作流条带、一个客户成果区、按月/按年的定价、一个 FAQ，以及一个干净的页脚。切换到<strong>平板</strong>和<strong>手机</strong>视图，确认响应式设计经得起考验。</p>\n<h2 id=\"step-4--refine-with-the-on-canvas-toolbar\">第 4 步 —— 用画布工具栏精修</h2>\n<p>右侧工具栏就是你打磨的地方，无需为琐碎改动浪费 token：</p>\n<ul>\n<li><strong>Screenshot</strong>——抓取网站的一张图片。</li>\n<li><strong>Comment</strong>——选中任意元素（比如英雄区标题）并描述一个改动，例如把某个词改成橙色主题色。可以批量攒几条评论一次提交，也可以直接发一条到聊天。</li>\n<li><strong>Marker</strong>——高亮页面上的任意区域并分享给 agent。</li>\n<li><strong>Element edit</strong>——直接更改选中元素的字体、宽度、颜色等等，让简单的微调永远不必整体重新生成。</li>\n</ul>\n<p>你还能用到缩放控制以及所有未处理评论的总览。在演示里，那个 “actually” 文字就在工具栏里当场被改成了橙色。</p>\n<h2 id=\"step-5--export-and-deploy\">第 5 步 —— 导出与部署</h2>\n<p>工具栏上方是<strong>下载</strong>选项——把项目导出为 <strong>PDF、图片、ZIP 或 HTML</strong>。这里还有<strong>存为模板</strong>，让你可以把这个设计当作未来项目的起点复用。</p>\n<p><strong>分享</strong>菜单才是有意思的部分。在那里你可以：</p>\n<ul>\n<li>一键<strong>部署到 Vercel</strong>——用一个访问令牌连接你的 Vercel 账户，然后点部署。</li>\n<li>用同样的方式<strong>部署到 Cloudflare</strong>。</li>\n<li><strong>在编辑器中打开</strong>，比如 Cursor 或 VS Code，或者在 Gemini CLI、Codex、Claude Code 这类 CLI 工具里打开。Open Design 会把生成的 HTML 连同它的 Skills 文件夹一起交给你，于是你可以把这个设计转成一个 Next.js 项目——或者你喜欢的任何框架。</li>\n</ul>\n<p>在<strong>设置</strong>里，你可以添加全局规则（例如“始终使用 TypeScript”）、像 Claude 的记忆功能那样存下有用的记忆，并配置<strong>媒体提供方</strong>——用于配音和音效的 ElevenLabs key，以及用于图像生成的 Nano Banana、OpenAI 或 OpenRouter。你还可以添加技能（有一个用于自动化浏览器任务的 agent-browser 技能，以及若干前端技能）、接入 MCP 服务器，并更改默认的项目位置。</p>\n<h2 id=\"tips-for-getting-more-out-of-it\">让它更好用的小贴士</h2>\n<ul>\n<li><strong>免费模型足够起步。</strong>整个演示站点都是用免费的 Gemini 档位生成的，效果依然很棒；当你想在正式工作上追求更高质量时，再上付费模型。</li>\n<li><strong>在提示前先加好插件</strong>，尤其当你知道自己会用到 3D 模型或设备外框时。</li>\n<li><strong>为改动选对工具</strong>——元素编辑器和评论能处理小改动，无需整体重建。</li>\n<li><strong>把出彩的布局存为模板</strong>，让下一个项目赢在起跑线。</li>\n</ul>\n<h2 id=\"faq\">常见问题</h2>\n<p><strong>Open Design 免费吗？</strong>\n是的——它在 Apache-2.0 下开源，本地运行免费。你只需为所连接的 agent 和媒体提供方的模型/API 用量付费，而且可以使用像 Gemini 那样的免费档位。</p>\n<p><strong>它支持哪些编码 agent？</strong>\n21+ 个 agent，包括 Claude Code、Codex CLI、Cursor、Gemini CLI 和 OpenCode。你从右上角菜单选择提供方。</p>\n<p><strong>它和 Claude Design 有什么不同？</strong>\n同样熟悉的手感，但它开源、本地优先、agent 可插拔——你不会被锁定在某一个模型或平台上，而且你可以按自己的方式导出或部署项目。</p>\n<p><strong>我能不离开应用就完成部署吗？</strong>\n可以——分享菜单一键部署到 Vercel 或 Cloudflare（你提供提供方的访问令牌），或者把代码交给 Cursor、VS Code 或某个 CLI agent。</p>\n<p><strong>要拿到好结果，我必须用付费模型吗？</strong>\n不必——对大多数落地页和前端设计来说，免费模型就已经足够能干了；只有当你想要更进阶的结果时，才切到付费模型。</p>\n<hr>\n<p><em>这份图文指南基于 Code A Program 的演示。观看上方完整视频，并<a href=\"https://www.youtube.com/watch?v=2AdKzkQyKkg\">订阅 Code A Program</a> 以获取更多实操向的 AI 工具视频。</em></p>",
  },
  "ja": {
    title: "Open Design：無料のオープンソース Claude Design 代替",
    summary: "Code A Program のデモに基づく解説——Open Design で AI ライティングツールの完全なランディングページを作る。コーディングエージェント（無料のものでも）を選び、プロンプトでデザインを生成し、キャンバス上の編集で仕上げ、そのままエクスポートするか Vercel または Cloudflare にワンクリックでデプロイ。",
    bodyHtml: "<p>Open Design はアイデアを、プロトタイプ、ウェブサイト、スライド、さらには HTML 動画へと変えます——すべてあなた自身のマシン上でローカルに動作します。このデモでは、Code A Program がデスクトップアプリをインストールし、コーディングエージェントを接続し、<em>Draft</em> という AI ライティングツールのための上質なランディングページを構築し、ワークスペースを離れることなく仕上げてデプロイします。実際の流れは <a href=\"https://www.youtube.com/watch?v=2AdKzkQyKkg\">Code A Program の動画</a>でご覧いただくか、続けて下記の記事版をお読みください。</p>\n<p><img src=\"/tutorials/open-design-free-open-source-alternative-code-a-program/01-workspace.webp\" alt=\"ローカルで動作している Open Design ワークスペース。\">\n<em>ローカルで動く Open Design：あなたが完全に制御できる、オープンソースでエージェントネイティブなデザインワークスペース——単一のモデルに縛られません。</em></p>\n<h2 id=\"what-is-open-design\">Open Design とは？</h2>\n<p>Open Design はオープンソースでローカルファーストのデザインプラットフォーム——Claude Design と Figma の無料代替です。特定のモデルプロバイダーに縛りつけるのではなく、<strong>あなたがすでに使っているコーディングエージェント上で動作します</strong>。つまり自分のエージェントと自分の key を持ち込めます。</p>\n<ul>\n<li><strong>オープンソース、Apache-2.0</strong>——一行残らず読み、セルフホストし、あるいは単にデスクトップアプリをダウンロード。</li>\n<li><strong>ローカルで動作</strong>——プロジェクトは他人のクラウドではなく、あなたのマシン上の自分のフォルダーに存在します。</li>\n<li><strong>エージェント持ち込み</strong>——Claude Code、Codex、Cursor、Gemini、OpenCode など 21 以上のコーディングエージェントに対応；どの CLI が生成を駆動するかはあなたが選びます。</li>\n<li><strong>プロトタイプにとどまらない</strong>——ウェブサイト、プロトタイプ、スライド、画像生成、さらには HTML 動画まで、すべてひとつのワークスペースから。</li>\n<li><strong>すぐ使える一式</strong>——129 の組み込みデザインシステムと 460 以上のプラグインで、白紙のキャンバスから始めることは決してありません。</li>\n</ul>\n<p>Claude Design を使ったことがあれば、すぐに馴染むはずです——Open Design は同じ落ち着いた体験を保ちつつ、その上にあなたが選んだモデルを載せます。</p>\n<h2 id=\"step-1--choose-your-agent-and-model\">ステップ 1 —— エージェントとモデルを選ぶ</h2>\n<p><a href=\"https://open-design.ai/\">open-design.ai</a> からデスクトップアプリをダウンロードしてインストールし、短いオンボーディングの質問に答えます。それでメインのチャット画面に入ります。</p>\n<p><strong>右上</strong>で AI エージェントのプロバイダーを選びます。ローカル CLI プロバイダーとしては、Claude Code、Codex CLI、Gemini CLI（無料の利用枠があります）、OpenCode などを選べます。デモでは、Code A Program は <strong>OpenCode と GLM 5.2 モデル</strong>を使っています。フロントエンド作業で強さを見せてきたからです——ただ肝心なのはその柔軟さです。あなたはひとつのモデルやプラットフォームに縛られません。</p>\n<h2 id=\"step-2--write-your-prompt\">ステップ 2 —— プロンプトを書く</h2>\n<p>チャットには参考資料用の<strong>ファイル添付</strong>オプションと、<strong>プラグイン</strong>のセクションがあります。Open Design にはビルド／テスト補助、3D モックアップ、モバイル・デスクトップのデバイスフレームなどをカバーする 460 以上のプラグインが付属します——だから 3D 要素やデバイスの外枠が必要なら、プロンプトと格闘するのではなくプラグインを追加すればいいのです。</p>\n<p><img src=\"/tutorials/open-design-free-open-source-alternative-code-a-program/plugin-library.webp\" alt=\"Open Design のプラグインライブラリ。\">\n<em>プラグインライブラリ：ビルド、テスト、3D モックアップ、デバイスフレームなどのための 460 以上のプラグイン——デザインに必要なものを追加しましょう。</em></p>\n<p>ではブリーフを貼り付けます。デモのプロンプトは、<strong>Draft という名の AI ライティングアシスタント向けの上質なランディングページ</strong>を求めています。抑制の効いたスレートブラック、アイボリー、エレクトリックオレンジのパレット、ライブのテキスト生成アニメーションを備えた大胆なエディトリアルなヒーロー、インタラクティブなライティングキャンバス、3 ステップのワークフロー、結果セクション、2 段階の料金表、FAQ、そして力強い最後の行動喚起——一方で、カード、グラデーション、グラスモーフィズム、ありふれたロボットの画像は明確に避けます。</p>\n<p>もうひとつ知っておく価値のあるレバーがあります：Apple、Airbnb、BMW、IBM、Spotify といったブランドの<strong>人気のデザインシステム</strong>を土台にできるのです。Code A Program は今回はスキップしていますが、特定の見た目に合わせたいときのために用意されています。</p>\n<h2 id=\"step-3--watch-it-build-and-self-check\">ステップ 3 —— ビルドとセルフチェックを見守る</h2>\n<p>プロンプトを送信すると、Open Design はプロジェクトの準備を始めます。約 1 分後、いくつかの<strong>追加質問</strong>をしてくることがあります——より良い結果のために答えるか、<strong>すべてスキップ</strong>を押して続行させましょう。</p>\n<p>デモでは、ランディングページ自体は約<strong>6 分</strong>で完成します。その後 Open Design は残りの時間を<strong>セルフチェック</strong>に費やします——構造を検証し、レイアウトを見直し、アニメーションを確認し、ビルド完了とする前に細かな問題を修正します。終わったら、<strong>プレゼンアイコン</strong>をクリックして新しいタブでサイトを開きます。</p>\n<p><img src=\"/tutorials/open-design-free-open-source-alternative-code-a-program/generated-prototype.webp\" alt=\"Open Design でプレビューした、生成済みのランディングページ。\">\n<em>生成された結果：ライブのタイピングアニメーション付きのエディトリアルなヒーロー、ワークフロー、結果、料金、FAQ、フッター——タブレットとモバイルにわたってレスポンシブ。</em></p>\n<p>その結果には、AI タイピングアニメーション付きのヒーロー、なめらかなスクロール効果、インタラクティブなエディターセクション、ワークフローの帯、顧客の結果セクション、月額／年額の料金、FAQ、そしてすっきりしたフッターが備わっています。<strong>タブレット</strong>と<strong>モバイル</strong>のビューに切り替えて、レスポンシブなデザインが崩れないか確認しましょう。</p>\n<h2 id=\"step-4--refine-with-the-on-canvas-toolbar\">ステップ 4 —— キャンバス上のツールバーで仕上げる</h2>\n<p>右側のツールバーは、些細な変更にトークンを浪費せずに磨き上げる場所です：</p>\n<ul>\n<li><strong>Screenshot</strong>——サイトの画像を取得します。</li>\n<li><strong>Comment</strong>——任意の要素（たとえばヒーローの見出し）を選び、ある単語をオレンジのテーマ色に塗り替えるといった変更を記述します。複数のコメントをまとめて一度に送るか、ひとつをそのままチャットへ送れます。</li>\n<li><strong>Marker</strong>——ページの任意の領域をハイライトしてエージェントに共有します。</li>\n<li><strong>Element edit</strong>——選択した要素のフォント、幅、色などを直接変更するので、簡単な微調整に完全な再生成は一切不要です。</li>\n</ul>\n<p>ズームコントロールと、開いているすべてのコメントの一覧も使えます。デモでは、あの 「actually」 という文字が、そのままツールバー上でオレンジに塗り替えられます。</p>\n<h2 id=\"step-5--export-and-deploy\">ステップ 5 —— エクスポートとデプロイ</h2>\n<p>ツールバーの上には<strong>ダウンロード</strong>オプションがあります——プロジェクトを <strong>PDF、画像、ZIP、または HTML</strong> としてエクスポートできます。さらに<strong>テンプレートとして保存</strong>もあり、このデザインを今後のプロジェクトの出発点として再利用できます。</p>\n<p>面白いのは<strong>共有</strong>メニューです。そこから次のことができます：</p>\n<ul>\n<li>ワンクリックで <strong>Vercel にデプロイ</strong>——アクセストークンで Vercel アカウントを接続し、デプロイを押すだけ。</li>\n<li>同じ要領で <strong>Cloudflare にデプロイ</strong>。</li>\n<li>Cursor や VS Code のような<strong>エディターで開く</strong>、あるいは Gemini CLI、Codex、Claude Code といった CLI ツールで開く。Open Design は生成された HTML とその Skills フォルダーを手渡すので、そのデザインを Next.js プロジェクト——あるいはお好みのどんなフレームワークにも変換できます。</li>\n</ul>\n<p><strong>設定</strong>では、グローバルルール（たとえば「常に TypeScript を使う」）を追加し、Claude のメモリ機能のように役立つメモリを保存し、<strong>メディアプロバイダー</strong>を構成できます——音声とサウンド用の ElevenLabs key、そして画像生成用の Nano Banana、OpenAI、または OpenRouter です。さらにスキルの追加（ブラウザ操作を自動化する agent-browser スキルや、いくつかのフロントエンド系スキルがあります）、MCP サーバーの接続、デフォルトのプロジェクト保存場所の変更もできます。</p>\n<h2 id=\"tips-for-getting-more-out-of-it\">もっと活用するためのヒント</h2>\n<ul>\n<li><strong>始めるには無料モデルで十分です。</strong>デモサイト全体は無料の Gemini 枠で生成されましたが、それでも見栄えは抜群です；本番の仕事でより高い品質が欲しいときに有料モデルを使いましょう。</li>\n<li><strong>プロンプトの前にプラグインを追加</strong>——3D モックアップやデバイスフレームが必要だと分かっているときは。</li>\n<li><strong>変更に合った正しいツールを使う</strong>——要素エディターとコメントは、完全な再ビルドなしに小さな微調整をこなします。</li>\n<li><strong>うまくいったレイアウトはテンプレートとして保存</strong>——次のプロジェクトを一歩先から始められます。</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>Open Design は無料ですか？</strong>\nはい——Apache-2.0 のもとオープンソースで、ローカルでの実行は無料です。接続するエージェントとメディアプロバイダーのモデル／API 使用量にのみ料金が発生し、Gemini のような無料枠も利用できます。</p>\n<p><strong>どのコーディングエージェントに対応していますか？</strong>\nClaude Code、Codex CLI、Cursor、Gemini CLI、OpenCode を含む 21 以上のエージェントです。プロバイダーは右上のメニューから選びます。</p>\n<p><strong>Claude Design とはどう違うのですか？</strong>\n馴染みのある手触りは同じですが、オープンソースでローカルファースト、そしてエージェント差し替え可能です——ひとつのモデルやプラットフォームに縛られず、プロジェクトを好きな方法でエクスポートやデプロイできます。</p>\n<p><strong>アプリを離れずにデプロイできますか？</strong>\nはい——共有メニューがワンクリックで Vercel または Cloudflare にデプロイします（プロバイダーのアクセストークンはあなたが用意します）。あるいはコードを Cursor、VS Code、CLI エージェントに手渡します。</p>\n<p><strong>良い結果を得るには有料モデルを使わないといけませんか？</strong>\nいいえ——ほとんどのランディングページやフロントエンドデザインには、無料モデルで十分に力を発揮します；より高度な結果が欲しいときにだけ有料モデルに切り替えましょう。</p>\n<hr>\n<p><em>この記事ガイドは Code A Program のデモに基づいています。上の完全な動画をご覧になり、より多くの実践的な AI ツール動画のために <a href=\"https://www.youtube.com/watch?v=2AdKzkQyKkg\">Code A Program を購読</a>してください。</em></p>",
  },
  "ko": {
    title: "Open Design: 무료 오픈소스 Claude Design 대안",
    summary: "Code A Program의 데모 기반 해설——Open Design에서 완전한 AI 글쓰기 도구 랜딩 페이지를 만듭니다. 코딩 에이전트(무료라도)를 고르고, 프롬프트로 디자인을 생성하고, 캔버스 편집으로 다듬은 뒤, 그대로 내보내거나 Vercel 또는 Cloudflare로 원클릭 배포하세요.",
    bodyHtml: "<p>Open Design는 아이디어를 프로토타입, 웹사이트, 슬라이드, 심지어 HTML 영상으로까지 바꿔 줍니다——모두 당신 자신의 머신에서 로컬로 동작합니다. 이 데모에서 Code A Program은 데스크톱 앱을 설치하고, 코딩 에이전트를 연결하고, <em>Draft</em>라는 AI 글쓰기 도구를 위한 고급스러운 랜딩 페이지를 만든 뒤, 작업 공간을 떠나지 않고 다듬어 배포합니다. 전체 과정을 <a href=\"https://www.youtube.com/watch?v=2AdKzkQyKkg\">Code A Program의 영상</a>에서 보거나, 계속해서 아래 글 버전을 읽어 보세요.</p>\n<p><img src=\"/tutorials/open-design-free-open-source-alternative-code-a-program/01-workspace.webp\" alt=\"로컬에서 실행 중인 Open Design 작업 공간.\">\n<em>로컬에서 실행되는 Open Design: 당신이 완전히 통제하는 오픈소스, 에이전트 네이티브 디자인 작업 공간——단일 모델에 묶이지 않습니다.</em></p>\n<h2 id=\"what-is-open-design\">Open Design란?</h2>\n<p>Open Design는 오픈소스이자 로컬 우선 디자인 플랫폼입니다——Claude Design과 Figma의 무료 대안이죠. 하나의 모델 제공자에 묶는 대신, <strong>당신이 이미 쓰고 있는 코딩 에이전트 위에서</strong> 동작합니다. 그래서 당신의 에이전트와 당신의 key를 가져와 쓸 수 있습니다.</p>\n<ul>\n<li><strong>오픈소스, Apache-2.0</strong>——한 줄 한 줄 읽고, 셀프호스팅하거나, 그냥 데스크톱 앱을 다운로드하세요.</li>\n<li><strong>로컬에서 실행</strong>——프로젝트는 남의 클라우드가 아니라 당신 머신의 당신 폴더에 존재합니다.</li>\n<li><strong>에이전트 가져오기</strong>——Claude Code, Codex, Cursor, Gemini, OpenCode 등 21개 이상의 코딩 에이전트를 지원합니다; 어떤 CLI가 생성을 이끌지는 당신이 고릅니다.</li>\n<li><strong>프로토타입 그 이상</strong>——웹사이트, 프로토타입, 슬라이드 덱, 이미지 생성, 심지어 HTML 영상까지 모두 하나의 작업 공간에서.</li>\n<li><strong>필요한 것은 다 들어 있음</strong>——내장 디자인 시스템 129종과 460개 이상의 플러그인으로, 결코 빈 캔버스에서 시작하지 않습니다.</li>\n</ul>\n<p>Claude Design를 써 봤다면 곧바로 익숙할 겁니다——Open Design는 똑같이 차분한 경험을 유지하면서, 그 위에 당신이 고른 모델을 얹어 줍니다.</p>\n<h2 id=\"step-1--choose-your-agent-and-model\">1단계 —— 에이전트와 모델 고르기</h2>\n<p><a href=\"https://open-design.ai/\">open-design.ai</a>에서 데스크톱 앱을 다운로드해 설치하고, 짧은 온보딩 질문에 답하세요. 그러면 메인 채팅 화면으로 들어갑니다.</p>\n<p><strong>오른쪽 위</strong>에서 AI 에이전트 제공자를 고르세요. 로컬 CLI 제공자로는 Claude Code, Codex CLI, Gemini CLI(무료 사용 한도가 있음), OpenCode 등을 고를 수 있습니다. 데모에서 Code A Program은 <strong>OpenCode와 GLM 5.2 모델</strong>을 씁니다. 프런트엔드 작업에서 강했기 때문이죠——하지만 핵심은 유연성입니다: 당신은 하나의 모델이나 플랫폼에 묶이지 않습니다.</p>\n<h2 id=\"step-2--write-your-prompt\">2단계 —— 프롬프트 작성하기</h2>\n<p>채팅에는 참고 자료용 <strong>파일 첨부</strong> 옵션과 <strong>플러그인</strong> 섹션이 있습니다. Open Design는 빌드·테스트 도우미, 3D 목업, 모바일·데스크톱 디바이스 프레임 등을 아우르는 460개 이상의 플러그인과 함께 제공됩니다——그러니 3D 요소나 디바이스 껍데기가 필요하면, 프롬프트와 씨름하는 대신 플러그인을 추가하세요.</p>\n<p><img src=\"/tutorials/open-design-free-open-source-alternative-code-a-program/plugin-library.webp\" alt=\"Open Design 플러그인 라이브러리.\">\n<em>플러그인 라이브러리: 빌드, 테스트, 3D 목업, 디바이스 프레임 등을 위한 460개 이상의 플러그인——디자인에 필요한 것을 추가하세요.</em></p>\n<p>이제 브리프를 붙여 넣으세요. 데모 프롬프트는 <strong>Draft라는 AI 글쓰기 어시스턴트를 위한 고급 랜딩 페이지</strong>를 요청합니다. 절제된 슬레이트 블랙, 아이보리, 일렉트릭 오렌지 팔레트, 실시간 텍스트 생성 애니메이션이 있는 대담한 에디토리얼 히어로, 인터랙티브 글쓰기 캔버스, 3단계 워크플로, 결과 섹션, 2단 요금표, FAQ, 그리고 강력한 마지막 행동 유도——동시에 카드, 그러데이션, 글래스모피즘, 진부한 로봇 이미지는 명확히 피합니다.</p>\n<p>알아 둘 만한 지렛대가 하나 더 있습니다: Apple, Airbnb, BMW, IBM, Spotify 같은 브랜드의 <strong>인기 디자인 시스템</strong>을 바탕으로 디자인을 만들 수 있습니다. Code A Program은 이번엔 건너뛰지만, 특정한 룩에 맞추고 싶을 때를 위해 준비되어 있습니다.</p>\n<h2 id=\"step-3--watch-it-build-and-self-check\">3단계 —— 빌드와 셀프 체크 지켜보기</h2>\n<p>프롬프트를 제출하면 Open Design가 프로젝트 준비를 시작합니다. 약 1분 뒤 몇 가지 <strong>후속 질문</strong>을 할 수도 있습니다——더 나은 결과를 위해 답하거나, <strong>모두 건너뛰기</strong>를 눌러 계속 진행하게 하세요.</p>\n<p>데모에서 랜딩 페이지 자체는 약 <strong>6분</strong> 만에 끝납니다. 그런 다음 Open Design는 남은 시간을 <strong>셀프 체크</strong>에 씁니다——구조를 검증하고, 레이아웃을 살피고, 애니메이션을 확인하고, 빌드 완료로 표시하기 전에 자잘한 문제를 고칩니다. 끝나면 <strong>프레젠트 아이콘</strong>을 클릭해 새 탭에서 사이트를 여세요.</p>\n<p><img src=\"/tutorials/open-design-free-open-source-alternative-code-a-program/generated-prototype.webp\" alt=\"Open Design에서 미리 본, 생성된 랜딩 페이지.\">\n<em>생성된 결과: 실시간 타이핑 애니메이션이 있는 에디토리얼 히어로, 워크플로, 결과, 요금, FAQ, 푸터——태블릿과 모바일 전반에서 반응형.</em></p>\n<p>결과에는 AI 타이핑 애니메이션 히어로, 매끄러운 스크롤 효과, 인터랙티브 에디터 섹션, 워크플로 스트립, 고객 결과 섹션, 월간/연간 요금, FAQ, 그리고 깔끔한 푸터가 담겨 있습니다. <strong>태블릿</strong>과 <strong>모바일</strong> 뷰로 전환해 반응형 디자인이 잘 버티는지 확인하세요.</p>\n<h2 id=\"step-4--refine-with-the-on-canvas-toolbar\">4단계 —— 캔버스 툴바로 다듬기</h2>\n<p>오른쪽 툴바는 사소한 변경에 토큰을 태우지 않고 다듬는 곳입니다:</p>\n<ul>\n<li><strong>Screenshot</strong>——사이트의 이미지를 캡처합니다.</li>\n<li><strong>Comment</strong>——아무 요소(예: 히어로 제목)를 선택하고, 어떤 단어를 오렌지 테마 색으로 바꾸는 것 같은 변경을 설명하세요. 여러 코멘트를 모아 한 번에 보내거나, 하나를 바로 채팅으로 보낼 수 있습니다.</li>\n<li><strong>Marker</strong>——페이지의 아무 영역이나 강조 표시해 에이전트에게 공유합니다.</li>\n<li><strong>Element edit</strong>——선택한 요소의 글꼴, 너비, 색상 등을 직접 바꿔서, 간단한 조정에는 전체 재생성이 결코 필요 없게 합니다.</li>\n</ul>\n<p>줌 컨트롤과 열려 있는 모든 코멘트의 보기도 제공됩니다. 데모에서 그 “actually” 텍스트는 툴바에서 바로 그 자리에서 오렌지로 바뀝니다.</p>\n<h2 id=\"step-5--export-and-deploy\">5단계 —— 내보내기와 배포</h2>\n<p>툴바 위에는 <strong>다운로드</strong> 옵션이 있습니다——프로젝트를 <strong>PDF, 이미지, ZIP 또는 HTML</strong>로 내보냅니다. <strong>템플릿으로 저장</strong>도 있어서, 이 디자인을 앞으로의 프로젝트 출발점으로 재사용할 수 있습니다.</p>\n<p>흥미로운 부분은 <strong>공유</strong> 메뉴입니다. 거기서 다음을 할 수 있습니다:</p>\n<ul>\n<li>원클릭으로 <strong>Vercel에 배포</strong>——액세스 토큰으로 Vercel 계정을 연결하고 배포를 누르세요.</li>\n<li>같은 방식으로 <strong>Cloudflare에 배포</strong>.</li>\n<li>Cursor나 VS Code 같은 <strong>에디터에서 열기</strong>, 또는 Gemini CLI, Codex, Claude Code 같은 CLI 도구에서 열기. Open Design는 생성된 HTML과 그 Skills 폴더를 함께 넘겨주므로, 이 디자인을 Next.js 프로젝트——또는 원하는 어떤 프레임워크로든 바꿀 수 있습니다.</li>\n</ul>\n<p><strong>설정</strong>에서는 전역 규칙(예: “항상 TypeScript 사용”)을 추가하고, Claude의 메모리 기능처럼 유용한 메모리를 저장하고, <strong>미디어 제공자</strong>를 구성할 수 있습니다——음성과 사운드용 ElevenLabs key, 그리고 이미지 생성용 Nano Banana, OpenAI 또는 OpenRouter. 또한 스킬 추가(브라우저 작업을 자동화하는 agent-browser 스킬과 여러 프런트엔드 스킬이 있습니다), MCP 서버 연결, 기본 프로젝트 위치 변경도 할 수 있습니다.</p>\n<h2 id=\"tips-for-getting-more-out-of-it\">더 잘 쓰기 위한 팁</h2>\n<ul>\n<li><strong>시작하기엔 무료 모델로 충분합니다.</strong> 데모 사이트 전체가 무료 Gemini 등급으로 생성되었는데도 여전히 멋져 보입니다; 실제 업무에서 더 높은 품질을 원할 때 유료 모델을 꺼내세요.</li>\n<li><strong>프롬프트 전에 플러그인을 추가하세요</strong>——3D 목업이나 디바이스 프레임이 필요할 걸 알고 있다면.</li>\n<li><strong>변경에 맞는 올바른 도구를 쓰세요</strong>——요소 에디터와 코멘트는 전체 재빌드 없이 작은 조정을 처리합니다.</li>\n<li><strong>잘된 레이아웃은 템플릿으로 저장</strong>——다음 프로젝트를 한발 앞서 시작하세요.</li>\n</ul>\n<h2 id=\"faq\">자주 묻는 질문</h2>\n<p><strong>Open Design는 무료인가요?</strong>\n네——Apache-2.0 하에 오픈소스이며 로컬 실행은 무료입니다. 연결하는 에이전트와 미디어 제공자의 모델/API 사용량에 대해서만 비용을 내며, Gemini 같은 무료 등급을 쓸 수 있습니다.</p>\n<p><strong>어떤 코딩 에이전트를 지원하나요?</strong>\nClaude Code, Codex CLI, Cursor, Gemini CLI, OpenCode를 포함해 21개 이상의 에이전트입니다. 제공자는 오른쪽 위 메뉴에서 고릅니다.</p>\n<p><strong>Claude Design과 어떻게 다른가요?</strong>\n익숙한 느낌은 같지만, 오픈소스이고 로컬 우선이며 에이전트를 갈아 끼울 수 있습니다——하나의 모델이나 플랫폼에 묶이지 않고, 프로젝트를 원하는 방식대로 내보내거나 배포할 수 있습니다.</p>\n<p><strong>앱을 떠나지 않고 배포할 수 있나요?</strong>\n네——공유 메뉴가 원클릭으로 Vercel이나 Cloudflare에 배포합니다(제공자 액세스 토큰은 당신이 제공). 또는 코드를 Cursor, VS Code, 또는 CLI 에이전트에 넘깁니다.</p>\n<p><strong>좋은 결과를 얻으려면 유료 모델을 써야 하나요?</strong>\n아니요——대부분의 랜딩 페이지와 프런트엔드 디자인에는 무료 모델이 이미 충분히 유능합니다; 더 고급 결과를 원할 때만 유료 모델로 전환하세요.</p>\n<hr>\n<p><em>이 글 가이드는 Code A Program의 데모를 기반으로 합니다. 위의 전체 영상을 보고, 더 많은 실습형 AI 도구 영상을 위해 <a href=\"https://www.youtube.com/watch?v=2AdKzkQyKkg\">Code A Program을 구독</a>하세요.</em></p>",
  },
  "de": {
    title: "Open Design: Die KOSTENLOSE quelloffene Claude-Design-Alternative",
    summary: "Basierend auf der Demo von Code A Program: Baue in Open Design eine komplette Landingpage für ein KI-Schreibtool — wähle einen Coding-Agenten (auch einen kostenlosen), prompte das Design, verfeinere es mit Edits auf der Canvas und exportiere dann oder deploye mit einem Klick auf Vercel oder Cloudflare.",
    bodyHtml: "<p>Open Design nimmt eine Idee und macht daraus Prototypen, Websites, Slides und sogar HTML-Videos — alles läuft lokal auf deinem eigenen Rechner. In dieser Demo installiert Code A Program die Desktop-App, verbindet einen Coding-Agenten und baut eine hochwertige Landingpage für ein KI-Schreibtool namens <em>Draft</em>, um sie dann zu verfeinern und zu deployen, ohne den Workspace zu verlassen. Sieh dir den kompletten Durchlauf im <a href=\"https://www.youtube.com/watch?v=2AdKzkQyKkg\">Video von Code A Program</a> an oder folge der schriftlichen Anleitung unten.</p>\n<p><img src=\"/tutorials/open-design-free-open-source-alternative-code-a-program/01-workspace.webp\" alt=\"Der lokal laufende Open-Design-Workspace.\">\n<em>Open Design lokal ausgeführt: ein quelloffener, agentennativer Design-Workspace, den du vollständig kontrollierst — nicht an ein einziges Modell gebunden.</em></p>\n<h2 id=\"what-is-open-design\">Was ist Open Design?</h2>\n<p>Open Design ist eine quelloffene, local-first Designplattform — eine kostenlose Alternative zu Claude Design und Figma. Statt dich an einen Modellanbieter zu binden, läuft sie <strong>auf dem Coding-Agenten, den du bereits nutzt</strong>, sodass du deinen eigenen Agenten und deinen eigenen key mitbringst.</p>\n<ul>\n<li><strong>Open Source, Apache-2.0</strong> — lies jede Zeile, hoste es selbst oder lade einfach die Desktop-App herunter.</li>\n<li><strong>Läuft lokal</strong> — Projekte liegen in deinen eigenen Ordnern auf deinem Rechner, nicht in fremder Cloud.</li>\n<li><strong>Bring deinen eigenen Agenten mit</strong> — 21+ Coding-Agenten werden unterstützt, darunter Claude Code, Codex, Cursor, Gemini, OpenCode und mehr; du wählst, welche CLI die Generierung antreibt.</li>\n<li><strong>Mehr als Prototypen</strong> — Websites, Prototypen, Slide-Decks, Bildgenerierung und sogar HTML-Video, alles aus einem Workspace.</li>\n<li><strong>Alles inklusive</strong> — 129 eingebaute Designsysteme und 460+ Plugins, damit du nie mit einer leeren Leinwand beginnst.</li>\n</ul>\n<p>Wenn du Claude Design genutzt hast, wirkt es sofort vertraut — Open Design behält dasselbe ruhige Erlebnis und legt dann dein gewähltes Modell oben drauf.</p>\n<h2 id=\"step-1--choose-your-agent-and-model\">Schritt 1 — Wähle deinen Agenten und dein Modell</h2>\n<p>Lade die Desktop-App von <a href=\"https://open-design.ai/\">open-design.ai</a> herunter, installiere sie und beantworte die kurzen Onboarding-Fragen. Das bringt dich direkt in die Haupt-Chat-Oberfläche.</p>\n<p>Wähle <strong>oben rechts</strong> deinen KI-Agenten-Anbieter. Als lokale CLI-Anbieter kannst du Claude Code, Codex CLI, Gemini CLI (mit kostenlosen Nutzungslimits), OpenCode und andere wählen. In der Demo nutzt Code A Program <strong>OpenCode mit dem Modell GLM 5.2</strong>, weil es bei Frontend-Arbeit stark war — der entscheidende Punkt ist aber die Flexibilität: Du bist nicht auf ein Modell oder eine Plattform festgelegt.</p>\n<h2 id=\"step-2--write-your-prompt\">Schritt 2 — Schreibe deinen Prompt</h2>\n<p>Der Chat hat eine Option <strong>Datei anhängen</strong> für Referenzmaterial sowie einen Bereich <strong>Plugins</strong>. Open Design bringt 460+ Plugins mit, die Build- und Test-Helfer, 3D-Mockups, mobile und Desktop-Geräterahmen und mehr abdecken — wenn du also 3D-Elemente oder eine Gerätehülle brauchst, fügst du das Plugin hinzu, statt mit dem Prompt zu ringen.</p>\n<p><img src=\"/tutorials/open-design-free-open-source-alternative-code-a-program/plugin-library.webp\" alt=\"Die Plugin-Bibliothek von Open Design.\">\n<em>Die Plugin-Bibliothek: 460+ Plugins für Bauen, Testen, 3D-Mockups, Geräterahmen und mehr — füge hinzu, was dein Design braucht.</em></p>\n<p>Jetzt fügst du ein Briefing ein. Der Demo-Prompt verlangt eine <strong>hochwertige Landingpage für einen KI-Schreibassistenten namens Draft</strong>, mit einer zurückhaltenden Palette aus Schieferschwarz, Elfenbein und Elektrik-Orange, einem markanten redaktionellen Hero mit einer Live-Textgenerierungs-Animation, einer interaktiven Schreib-Canvas, einem dreistufigen Workflow, einem Ergebnisbereich, einer zweistufigen Preistabelle, einem FAQ und einem starken abschließenden Call to Action — während Cards, Verläufe, Glasmorphismus und generische Roboter-Bilder ausdrücklich vermieden werden.</p>\n<p>Es gibt noch einen Hebel, den man kennen sollte: Du kannst ein Design auf einem <strong>beliebten Designsystem</strong> von Marken wie Apple, Airbnb, BMW, IBM oder Spotify aufbauen. Code A Program überspringt das für diesen Durchlauf, aber es steht bereit, wenn du einen bestimmten Look treffen willst.</p>\n<h2 id=\"step-3--watch-it-build-and-self-check\">Schritt 3 — Sieh beim Bauen und Selbstprüfen zu</h2>\n<p>Sende den Prompt ab, und Open Design beginnt, das Projekt vorzubereiten. Nach etwa einer Minute stellt es vielleicht ein paar <strong>Rückfragen</strong> — beantworte sie für bessere Ergebnisse oder klicke <strong>alle überspringen</strong> und lass es weitermachen.</p>\n<p>In der Demo ist die Landingpage selbst nach etwa <strong>sechs Minuten</strong> fertig. Open Design verbringt die restliche Zeit dann mit <strong>Selbstprüfungen</strong> — es verifiziert die Struktur, überprüft das Layout, kontrolliert Animationen und behebt kleine Probleme, bevor es den Build als fertig markiert. Wenn es soweit ist, klicke auf das <strong>Präsentationssymbol</strong>, um die Seite in einem neuen Tab zu öffnen.</p>\n<p><img src=\"/tutorials/open-design-free-open-source-alternative-code-a-program/generated-prototype.webp\" alt=\"Eine generierte Landingpage in der Vorschau von Open Design.\">\n<em>Das generierte Ergebnis: ein redaktioneller Hero mit Live-Tippanimation, Workflow, Ergebnisse, Preise, FAQ und Footer — responsiv über Tablet und Mobil hinweg.</em></p>\n<p>Das Ergebnis trägt einen Hero mit KI-Tippanimation, sanfte Scroll-Effekte, einen interaktiven Editor-Bereich, einen Workflow-Streifen, einen Kundenergebnis-Bereich, monatliche/jährliche Preise, ein FAQ und einen aufgeräumten Footer. Wechsle in die <strong>Tablet</strong>- und <strong>Mobil</strong>-Ansicht, um zu bestätigen, dass das responsive Design hält.</p>\n<h2 id=\"step-4--refine-with-the-on-canvas-toolbar\">Schritt 4 — Verfeinern mit der Toolbar auf der Canvas</h2>\n<p>Die rechte Toolbar ist der Ort, an dem du polierst, ohne Tokens für triviale Änderungen zu verbrennen:</p>\n<ul>\n<li><strong>Screenshot</strong> — mach ein Bild der Seite.</li>\n<li><strong>Comment</strong> — wähle ein beliebiges Element (etwa die Hero-Überschrift) und beschreibe eine Änderung, zum Beispiel ein Wort in der orangen Themenfarbe umzufärben. Bündle mehrere Kommentare und sende sie auf einmal ab oder schicke einen direkt in den Chat.</li>\n<li><strong>Marker</strong> — hebe einen beliebigen Bereich der Seite hervor und teile ihn mit dem Agenten.</li>\n<li><strong>Element edit</strong> — ändere Schriften, Breite, Farben und mehr direkt an einem ausgewählten Element, sodass einfache Feinheiten nie eine komplette Neugenerierung brauchen.</li>\n</ul>\n<p>Du bekommst außerdem Zoom-Steuerungen und eine Übersicht aller offenen Kommentare. In der Demo färbt sich der Text „actually“ direkt dort in der Toolbar orange um.</p>\n<h2 id=\"step-5--export-and-deploy\">Schritt 5 — Exportieren und deployen</h2>\n<p>Über der Toolbar liegt die Option <strong>Herunterladen</strong> — exportiere das Projekt als <strong>PDF, Bild, ZIP oder HTML</strong>. Es gibt auch <strong>als Vorlage speichern</strong>, sodass du dieses Design als Ausgangspunkt für künftige Projekte wiederverwenden kannst.</p>\n<p>Der interessante Teil ist das Menü <strong>Teilen</strong>. Von dort aus kannst du:</p>\n<ul>\n<li>mit einem Klick <strong>auf Vercel deployen</strong> — verbinde dein Vercel-Konto mit einem Access-Token und klicke auf Deploy.</li>\n<li>auf dieselbe Weise <strong>auf Cloudflare deployen</strong>.</li>\n<li><strong>in einem Editor öffnen</strong> wie Cursor oder VS Code, oder in CLI-Tools wie Gemini CLI, Codex und Claude Code. Open Design übergibt das generierte HTML samt seinem Skills-Ordner, sodass du das Design in ein Next.js-Projekt — oder ein beliebiges Framework — umwandeln kannst.</li>\n</ul>\n<p>Unter <strong>Einstellungen</strong> kannst du globale Regeln hinzufügen (zum Beispiel „immer TypeScript verwenden“), nützliche Memories speichern wie bei Claudes Memory-Funktion und <strong>Medienanbieter</strong> konfigurieren — einen ElevenLabs-key für Stimme und Sound sowie Nano Banana, OpenAI oder OpenRouter für die Bildgenerierung. Du kannst außerdem Skills hinzufügen (es gibt einen agent-browser-Skill zum Automatisieren von Browser-Aufgaben und mehrere Frontend-Skills), MCP-Server anbinden und den Standard-Speicherort für Projekte ändern.</p>\n<h2 id=\"tips-for-getting-more-out-of-it\">Tipps, um mehr herauszuholen</h2>\n<ul>\n<li><strong>Kostenlose Modelle reichen für den Anfang.</strong> Die gesamte Demo-Seite wurde mit einer kostenlosen Gemini-Stufe generiert und sieht trotzdem großartig aus; greif zu einem bezahlten Modell, wenn du bei echter Arbeit höhere Qualität willst.</li>\n<li><strong>Füge Plugins vor dem Prompten hinzu</strong>, wenn du weißt, dass du 3D-Mockups oder Geräterahmen brauchst.</li>\n<li><strong>Nutze das richtige Werkzeug für die Änderung</strong> — der Element-Editor und Kommentare erledigen kleine Feinheiten ohne kompletten Neuaufbau.</li>\n<li><strong>Speichere gelungene Layouts als Vorlagen</strong>, damit dein nächstes Projekt einen Vorsprung hat.</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>Ist Open Design kostenlos?</strong>\nJa — es ist quelloffen unter Apache-2.0 und läuft lokal kostenlos. Du zahlst nur für die Modell-/API-Nutzung des jeweiligen Agenten und der Medienanbieter, die du verbindest, und du kannst kostenlose Stufen wie die von Gemini nutzen.</p>\n<p><strong>Welche Coding-Agenten werden unterstützt?</strong>\n21+ Agenten, darunter Claude Code, Codex CLI, Cursor, Gemini CLI und OpenCode. Den Anbieter wählst du über das Menü oben rechts.</p>\n<p><strong>Wie unterscheidet es sich von Claude Design?</strong>\nDasselbe vertraute Gefühl, aber quelloffen, local-first und agenten-steckbar — du bist nicht an ein Modell oder eine Plattform gebunden und kannst dein Projekt exportieren oder deployen, wie du willst.</p>\n<p><strong>Kann ich deployen, ohne die App zu verlassen?</strong>\nJa — das Teilen-Menü deployt mit einem Klick auf Vercel oder Cloudflare (du lieferst das Access-Token des Anbieters) oder übergibt den Code an Cursor, VS Code oder einen CLI-Agenten.</p>\n<p><strong>Muss ich für gute Ergebnisse ein bezahltes Modell verwenden?</strong>\nNein — für die meisten Landingpages und Frontend-Designs sind kostenlose Modelle bereits leistungsfähig genug; wechsle nur dann zu einem bezahlten Modell, wenn du fortgeschrittenere Ergebnisse willst.</p>\n<hr>\n<p><em>Diese schriftliche Anleitung basiert auf der Demo von Code A Program. Sieh dir das vollständige Video oben an und <a href=\"https://www.youtube.com/watch?v=2AdKzkQyKkg\">abonniere Code A Program</a> für weitere praxisnahe KI-Tool-Videos.</em></p>",
  },
  "fr": {
    title: "Open Design : l’alternative open source GRATUITE à Claude Design",
    summary: "D’après la démo de Code A Program : construisez dans Open Design une landing page complète pour un outil d’écriture IA — choisissez un agent de codage (même gratuit), générez le design par un prompt, peaufinez-le avec des retouches sur le canevas, puis exportez ou déployez en un clic sur Vercel ou Cloudflare.",
    bodyHtml: "<p>Open Design prend une idée et la transforme en prototypes, sites web, slides et même vidéos HTML — le tout s’exécutant en local sur votre propre machine. Dans cette démo, Code A Program installe l’application de bureau, connecte un agent de codage et construit une landing page haut de gamme pour un outil d’écriture IA nommé <em>Draft</em>, puis la peaufine et la déploie sans jamais quitter l’espace de travail. Regardez le déroulé complet dans la <a href=\"https://www.youtube.com/watch?v=2AdKzkQyKkg\">vidéo de Code A Program</a>, ou suivez le guide écrit ci-dessous.</p>\n<p><img src=\"/tutorials/open-design-free-open-source-alternative-code-a-program/01-workspace.webp\" alt=\"L’espace de travail Open Design fonctionnant en local.\">\n<em>Open Design en local : un espace de travail de design open source et agent-native que vous contrôlez entièrement — non verrouillé sur un seul modèle.</em></p>\n<h2 id=\"what-is-open-design\">Qu’est-ce qu’Open Design ?</h2>\n<p>Open Design est une plateforme de design open source et local-first — une alternative gratuite à Claude Design et Figma. Au lieu de vous lier à un fournisseur de modèle, elle fonctionne <strong>par-dessus l’agent de codage que vous utilisez déjà</strong>, si bien que vous apportez votre propre agent et votre propre key.</p>\n<ul>\n<li><strong>Open source, Apache-2.0</strong> — lisez chaque ligne, auto-hébergez-la, ou téléchargez simplement l’application de bureau.</li>\n<li><strong>Fonctionne en local</strong> — les projets vivent dans vos propres dossiers sur votre machine, pas dans le cloud d’un tiers.</li>\n<li><strong>Apportez votre propre agent</strong> — plus de 21 agents de codage sont pris en charge, dont Claude Code, Codex, Cursor, Gemini, OpenCode et d’autres ; vous choisissez quelle CLI pilote la génération.</li>\n<li><strong>Plus que des prototypes</strong> — sites web, prototypes, decks de slides, génération d’images et même vidéo HTML, le tout depuis un seul espace de travail.</li>\n<li><strong>Tout est inclus</strong> — 129 design systems intégrés et plus de 460 plugins pour ne jamais partir d’une toile vierge.</li>\n</ul>\n<p>Si vous avez utilisé Claude Design, la sensation vous sera immédiatement familière — Open Design conserve la même expérience posée, puis y ajoute le modèle de votre choix.</p>\n<h2 id=\"step-1--choose-your-agent-and-model\">Étape 1 — Choisissez votre agent et votre modèle</h2>\n<p>Téléchargez l’application de bureau depuis <a href=\"https://open-design.ai/\">open-design.ai</a>, installez-la et répondez aux courtes questions d’intégration. Cela vous dépose directement dans l’interface de chat principale.</p>\n<p>En <strong>haut à droite</strong>, choisissez votre fournisseur d’agent IA. Comme fournisseurs CLI locaux, vous pouvez choisir Claude Code, Codex CLI, Gemini CLI (qui a des quotas gratuits), OpenCode et d’autres. Dans la démo, Code A Program utilise <strong>OpenCode avec le modèle GLM 5.2</strong> parce qu’il s’est montré solide pour le front-end — mais l’essentiel, c’est la flexibilité : vous n’êtes verrouillé ni sur un modèle ni sur une plateforme.</p>\n<h2 id=\"step-2--write-your-prompt\">Étape 2 — Rédigez votre prompt</h2>\n<p>Le chat propose une option <strong>joindre un fichier</strong> pour le matériel de référence, ainsi qu’une section <strong>plugins</strong>. Open Design est livré avec plus de 460 plugins couvrant des assistants de build et de test, des maquettes 3D, des cadres d’appareils mobiles et de bureau, et bien plus — si vous avez besoin d’éléments 3D ou d’une coque d’appareil, vous ajoutez le plugin plutôt que de vous battre avec le prompt.</p>\n<p><img src=\"/tutorials/open-design-free-open-source-alternative-code-a-program/plugin-library.webp\" alt=\"La bibliothèque de plugins d’Open Design.\">\n<em>La bibliothèque de plugins : plus de 460 plugins pour construire, tester, faire des maquettes 3D, des cadres d’appareils et plus — ajoutez ce dont votre design a besoin.</em></p>\n<p>Collez maintenant un brief. Le prompt de démo demande une <strong>landing page haut de gamme pour un assistant d’écriture IA nommé Draft</strong>, avec une palette sobre noir ardoise, ivoire et orange électrique, un hero éditorial audacieux doté d’une animation de génération de texte en direct, un canevas d’écriture interactif, un workflow en trois étapes, une section de résultats, une grille tarifaire à deux niveaux, une FAQ et un appel à l’action final percutant — tout en évitant explicitement les cartes, les dégradés, le glassmorphisme et l’imagerie de robot générique.</p>\n<p>Il y a un levier de plus à connaître : vous pouvez fonder un design sur un <strong>design system populaire</strong> de marques comme Apple, Airbnb, BMW, IBM ou Spotify. Code A Program le laisse de côté pour ce run, mais il est là quand vous voulez coller à un look précis.</p>\n<h2 id=\"step-3--watch-it-build-and-self-check\">Étape 3 — Regardez-le construire et s’auto-vérifier</h2>\n<p>Envoyez le prompt et Open Design commence à préparer le projet. Après environ une minute, il peut poser quelques <strong>questions de suivi</strong> — répondez-y pour de meilleurs résultats, ou cliquez sur <strong>tout ignorer</strong> et laissez-le continuer.</p>\n<p>Dans la démo, la landing page elle-même se termine en environ <strong>six minutes</strong>. Open Design passe ensuite le temps restant à effectuer des <strong>auto-vérifications</strong> — vérifier la structure, revoir la mise en page, contrôler les animations et corriger de petits problèmes avant de marquer le build comme terminé. Une fois prêt, cliquez sur l’<strong>icône de présentation</strong> pour ouvrir le site dans un nouvel onglet.</p>\n<p><img src=\"/tutorials/open-design-free-open-source-alternative-code-a-program/generated-prototype.webp\" alt=\"Une landing page générée, prévisualisée dans Open Design.\">\n<em>Le résultat généré : un hero éditorial avec une animation de frappe en direct, un workflow, des résultats, une tarification, une FAQ et un footer — responsive sur tablette et mobile.</em></p>\n<p>Le résultat comporte un hero avec animation de frappe IA, des effets de défilement fluides, une section d’éditeur interactive, une bande de workflow, une section de résultats clients, une tarification mensuelle/annuelle, une FAQ et un footer épuré. Passez aux vues <strong>tablette</strong> et <strong>mobile</strong> pour confirmer que le design responsive tient la route.</p>\n<h2 id=\"step-4--refine-with-the-on-canvas-toolbar\">Étape 4 — Peaufinez avec la barre d’outils sur le canevas</h2>\n<p>La barre d’outils de droite est l’endroit où vous peaufinez sans brûler de tokens sur des changements triviaux :</p>\n<ul>\n<li><strong>Screenshot</strong> — capturez une image du site.</li>\n<li><strong>Comment</strong> — sélectionnez n’importe quel élément (par exemple le titre du hero) et décrivez un changement, comme recolorer un mot dans le thème orange. Regroupez plusieurs commentaires et envoyez-les d’un coup, ou envoyez-en un directement au chat.</li>\n<li><strong>Marker</strong> — surlignez n’importe quelle zone de la page et partagez-la avec l’agent.</li>\n<li><strong>Element edit</strong> — changez directement les polices, la largeur, les couleurs et plus encore sur un élément sélectionné, pour que les petits ajustements ne nécessitent jamais une régénération complète.</li>\n</ul>\n<p>Vous disposez aussi de contrôles de zoom et d’une vue de tous les commentaires ouverts. Dans la démo, le texte « actually » est recoloré en orange directement là, dans la barre d’outils.</p>\n<h2 id=\"step-5--export-and-deploy\">Étape 5 — Exportez et déployez</h2>\n<p>Au-dessus de la barre d’outils se trouve l’option <strong>télécharger</strong> — exportez le projet en <strong>PDF, image, ZIP ou HTML</strong>. Il y a aussi <strong>enregistrer comme modèle</strong>, pour réutiliser ce design comme point de départ de futurs projets.</p>\n<p>Le menu <strong>partager</strong> est la partie intéressante. De là, vous pouvez :</p>\n<ul>\n<li><strong>déployer sur Vercel</strong> en un clic — connectez votre compte Vercel avec un jeton d’accès et cliquez sur déployer.</li>\n<li><strong>déployer sur Cloudflare</strong> de la même façon.</li>\n<li><strong>ouvrir dans un éditeur</strong> comme Cursor ou VS Code, ou dans des outils CLI comme Gemini CLI, Codex et Claude Code. Open Design vous remet le HTML généré ainsi que son dossier Skills, afin que vous puissiez convertir le design en projet Next.js — ou dans n’importe quel framework de votre choix.</li>\n</ul>\n<p>Dans <strong>paramètres</strong>, vous pouvez ajouter des règles globales (par exemple « toujours utiliser TypeScript »), stocker des mémoires utiles comme la fonction de mémoire de Claude, et configurer des <strong>fournisseurs de médias</strong> — une key ElevenLabs pour la voix et le son, ainsi que Nano Banana, OpenAI ou OpenRouter pour la génération d’images. Vous pouvez aussi ajouter des skills (il existe un skill agent-browser pour automatiser des tâches de navigation, et plusieurs skills front-end), brancher des serveurs MCP et changer l’emplacement par défaut des projets.</p>\n<h2 id=\"tips-for-getting-more-out-of-it\">Conseils pour en tirer davantage</h2>\n<ul>\n<li><strong>Les modèles gratuits suffisent pour démarrer.</strong> Tout le site de démo a été généré avec un palier Gemini gratuit et reste superbe ; passez à un modèle payant quand vous voulez une meilleure qualité sur du travail réel.</li>\n<li><strong>Ajoutez les plugins avant de prompter</strong> quand vous savez que vous aurez besoin de maquettes 3D ou de cadres d’appareils.</li>\n<li><strong>Utilisez le bon outil pour le changement</strong> — l’éditeur d’éléments et les commentaires gèrent les petits ajustements sans reconstruction complète.</li>\n<li><strong>Enregistrez les mises en page réussies comme modèles</strong> pour que votre prochain projet démarre en avance.</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>Open Design est-il gratuit ?</strong>\nOui — il est open source sous Apache-2.0 et s’exécute gratuitement en local. Vous ne payez que pour l’usage du modèle/API de l’agent et des fournisseurs de médias que vous connectez, et vous pouvez utiliser des paliers gratuits comme celui de Gemini.</p>\n<p><strong>Quels agents de codage prend-il en charge ?</strong>\nPlus de 21 agents, dont Claude Code, Codex CLI, Cursor, Gemini CLI et OpenCode. Vous choisissez le fournisseur dans le menu en haut à droite.</p>\n<p><strong>En quoi diffère-t-il de Claude Design ?</strong>\nLa même sensation familière, mais open source, local-first et à agent interchangeable — vous n’êtes verrouillé ni sur un modèle ni sur une plateforme, et vous pouvez exporter ou déployer votre projet comme vous le souhaitez.</p>\n<p><strong>Puis-je déployer sans quitter l’application ?</strong>\nOui — le menu partager déploie sur Vercel ou Cloudflare en un clic (vous fournissez le jeton d’accès du fournisseur), ou remet le code à Cursor, VS Code ou un agent CLI.</p>\n<p><strong>Dois-je utiliser un modèle payant pour de bons résultats ?</strong>\nNon — pour la plupart des landing pages et des designs front-end, les modèles gratuits sont déjà assez performants ; passez à un modèle payant seulement lorsque vous voulez des résultats plus avancés.</p>\n<hr>\n<p><em>Ce guide écrit est basé sur la démo de Code A Program. Regardez la vidéo complète ci-dessus, et <a href=\"https://www.youtube.com/watch?v=2AdKzkQyKkg\">abonnez-vous à Code A Program</a> pour d’autres vidéos pratiques sur les outils IA.</em></p>",
  },
  "ru": {
    title: "Open Design: БЕСПЛАТНАЯ open-source альтернатива Claude Design",
    summary: "По мотивам демо Code A Program: соберите в Open Design полноценный лендинг для ИИ-инструмента для письма — выберите кодинг-агента (даже бесплатного), создайте дизайн по промпту, доведите его правками на холсте, а затем экспортируйте или разверните в один клик на Vercel или Cloudflare.",
    bodyHtml: "<p>Open Design берёт идею и превращает её в прототипы, сайты, слайды и даже HTML-видео — и всё это работает локально на вашей собственной машине. В этом демо Code A Program устанавливает десктопное приложение, подключает кодинг-агента и собирает премиальный лендинг для ИИ-инструмента для письма под названием <em>Draft</em>, а затем дорабатывает и разворачивает его, не покидая рабочее пространство. Посмотрите весь процесс в <a href=\"https://www.youtube.com/watch?v=2AdKzkQyKkg\">видео Code A Program</a> или следуйте текстовому руководству ниже.</p>\n<p><img src=\"/tutorials/open-design-free-open-source-alternative-code-a-program/01-workspace.webp\" alt=\"Рабочее пространство Open Design, запущенное локально.\">\n<em>Open Design, запущенный локально: open-source, agent-native рабочее пространство для дизайна, которое вы полностью контролируете — без привязки к одной модели.</em></p>\n<h2 id=\"what-is-open-design\">Что такое Open Design?</h2>\n<p>Open Design — это open-source, local-first платформа для дизайна, бесплатная альтернатива Claude Design и Figma. Вместо того чтобы привязывать вас к одному поставщику моделей, она работает <strong>поверх кодинг-агента, которым вы уже пользуетесь</strong>, так что вы приносите своего агента и свой key.</p>\n<ul>\n<li><strong>Open source, Apache-2.0</strong> — читайте каждую строку, разворачивайте у себя или просто скачайте десктопное приложение.</li>\n<li><strong>Работает локально</strong> — проекты живут в ваших собственных папках на вашей машине, а не в чужом облаке.</li>\n<li><strong>Приносите своего агента</strong> — поддерживается 21+ кодинг-агент, включая Claude Code, Codex, Cursor, Gemini, OpenCode и другие; вы сами выбираете, какая CLI управляет генерацией.</li>\n<li><strong>Больше, чем прототипы</strong> — сайты, прототипы, слайд-деки, генерация изображений и даже HTML-видео, всё из одного рабочего пространства.</li>\n<li><strong>Всё в комплекте</strong> — 129 встроенных дизайн-систем и 460+ плагинов, чтобы вы никогда не начинали с чистого листа.</li>\n</ul>\n<p>Если вы пользовались Claude Design, ощущение будет мгновенно знакомым — Open Design сохраняет тот же спокойный опыт, а сверху добавляет выбранную вами модель.</p>\n<h2 id=\"step-1--choose-your-agent-and-model\">Шаг 1 — Выберите агента и модель</h2>\n<p>Скачайте десктопное приложение с <a href=\"https://open-design.ai/\">open-design.ai</a>, установите его и ответьте на короткие вопросы онбординга. Это выведет вас прямо в основной интерфейс чата.</p>\n<p>В <strong>правом верхнем углу</strong> выберите провайдера ИИ-агента. Из локальных CLI-провайдеров можно выбрать Claude Code, Codex CLI, Gemini CLI (у неё есть бесплатные лимиты), OpenCode и другие. В демо Code A Program использует <strong>OpenCode с моделью GLM 5.2</strong>, потому что она хорошо показывала себя во фронтенд-работе — но ключевое здесь гибкость: вы не привязаны ни к одной модели или платформе.</p>\n<h2 id=\"step-2--write-your-prompt\">Шаг 2 — Напишите промпт</h2>\n<p>В чате есть опция <strong>прикрепить файл</strong> для справочных материалов, а также раздел <strong>плагинов</strong>. Open Design поставляется с 460+ плагинами, охватывающими помощников для сборки и тестов, 3D-макеты, рамки мобильных и десктопных устройств и многое другое — так что если вам нужны 3D-элементы или корпус устройства, вы добавляете плагин, а не боретесь с промптом.</p>\n<p><img src=\"/tutorials/open-design-free-open-source-alternative-code-a-program/plugin-library.webp\" alt=\"Библиотека плагинов Open Design.\">\n<em>Библиотека плагинов: 460+ плагинов для сборки, тестирования, 3D-макетов, рамок устройств и не только — добавьте то, что нужно вашему дизайну.</em></p>\n<p>Теперь вставьте бриф. Промпт из демо просит <strong>премиальный лендинг для ИИ-ассистента для письма под названием Draft</strong>, со сдержанной палитрой из сланцево-чёрного, слоновой кости и электрик-оранжевого, смелым редакционным hero с анимацией живой генерации текста, интерактивным холстом для письма, трёхшаговым воркфлоу, секцией результатов, двухуровневой таблицей цен, FAQ и сильным финальным призывом к действию — при этом явно избегая карточек, градиентов, гласморфизма и шаблонных изображений роботов.</p>\n<p>Есть ещё один рычаг, о котором стоит знать: вы можете строить дизайн на основе <strong>популярной дизайн-системы</strong> брендов вроде Apple, Airbnb, BMW, IBM или Spotify. В этом прогоне Code A Program его пропускает, но он под рукой, когда вы хотите попасть в конкретный визуальный стиль.</p>\n<h2 id=\"step-3--watch-it-build-and-self-check\">Шаг 3 — Смотрите, как он строит и проверяет себя</h2>\n<p>Отправьте промпт, и Open Design начнёт готовить проект. Примерно через минуту он может задать несколько <strong>уточняющих вопросов</strong> — ответьте на них ради лучшего результата или нажмите <strong>пропустить все</strong> и позвольте ему продолжить.</p>\n<p>В демо сам лендинг готов примерно за <strong>шесть минут</strong>. Затем Open Design тратит оставшееся время на <strong>самопроверки</strong> — проверяет структуру, пересматривает вёрстку, контролирует анимации и устраняет мелкие проблемы, прежде чем отметить сборку завершённой. Когда он закончит, нажмите <strong>иконку презентации</strong>, чтобы открыть сайт в новой вкладке.</p>\n<p><img src=\"/tutorials/open-design-free-open-source-alternative-code-a-program/generated-prototype.webp\" alt=\"Сгенерированный лендинг в предпросмотре Open Design.\">\n<em>Сгенерированный результат: редакционный hero с живой анимацией печати, воркфлоу, результаты, цены, FAQ и футер — адаптивно на планшете и мобильном.</em></p>\n<p>Результат несёт hero с ИИ-анимацией печати, плавные эффекты прокрутки, интерактивную секцию редактора, полосу воркфлоу, секцию результатов клиентов, помесячные/погодовые цены, FAQ и аккуратный футер. Переключитесь на виды <strong>планшет</strong> и <strong>мобильный</strong>, чтобы убедиться, что адаптивный дизайн держится.</p>\n<h2 id=\"step-4--refine-with-the-on-canvas-toolbar\">Шаг 4 — Доводка с помощью панели на холсте</h2>\n<p>Правая панель инструментов — место, где вы наводите лоск, не сжигая токены на пустячные правки:</p>\n<ul>\n<li><strong>Screenshot</strong> — сделайте снимок сайта.</li>\n<li><strong>Comment</strong> — выделите любой элемент (скажем, заголовок hero) и опишите изменение, например перекрасить одно слово в оранжевый тематический цвет. Соберите несколько комментариев и отправьте их разом или пошлите один прямо в чат.</li>\n<li><strong>Marker</strong> — подсветите любую область страницы и поделитесь ею с агентом.</li>\n<li><strong>Element edit</strong> — напрямую меняйте шрифты, ширину, цвета и прочее у выбранного элемента, так что простым правкам никогда не нужна полная регенерация.</li>\n</ul>\n<p>Вам также доступны элементы управления масштабом и обзор всех открытых комментариев. В демо текст «actually» перекрашивается в оранжевый прямо там, в панели инструментов.</p>\n<h2 id=\"step-5--export-and-deploy\">Шаг 5 — Экспорт и деплой</h2>\n<p>Над панелью инструментов — опция <strong>скачать</strong>: экспортируйте проект как <strong>PDF, изображение, ZIP или HTML</strong>. Есть и <strong>сохранить как шаблон</strong>, чтобы переиспользовать этот дизайн как отправную точку для будущих проектов.</p>\n<p>Самое интересное — меню <strong>поделиться</strong>. Оттуда вы можете:</p>\n<ul>\n<li><strong>развернуть на Vercel</strong> в один клик — подключите аккаунт Vercel токеном доступа и нажмите deploy.</li>\n<li><strong>развернуть на Cloudflare</strong> тем же способом.</li>\n<li><strong>открыть в редакторе</strong> вроде Cursor или VS Code, либо в CLI-инструментах вроде Gemini CLI, Codex и Claude Code. Open Design передаёт сгенерированный HTML вместе с папкой Skills, так что вы можете превратить дизайн в проект Next.js — или в любой другой фреймворк по вкусу.</li>\n</ul>\n<p>В <strong>настройках</strong> можно добавить глобальные правила (например, «всегда использовать TypeScript»), сохранять полезные memories, как в функции памяти Claude, и настроить <strong>поставщиков медиа</strong> — key ElevenLabs для голоса и звука, а также Nano Banana, OpenAI или OpenRouter для генерации изображений. Ещё можно добавлять скиллы (есть скилл agent-browser для автоматизации задач в браузере и несколько фронтенд-скиллов), подключать MCP-серверы и менять расположение проектов по умолчанию.</p>\n<h2 id=\"tips-for-getting-more-out-of-it\">Советы, как выжать больше</h2>\n<ul>\n<li><strong>Для старта хватает бесплатных моделей.</strong> Весь демо-сайт был сгенерирован на бесплатном тарифе Gemini и всё равно выглядит отлично; берите платную модель, когда хотите более высокое качество в реальной работе.</li>\n<li><strong>Добавляйте плагины до промпта</strong>, если знаете, что понадобятся 3D-макеты или рамки устройств.</li>\n<li><strong>Используйте правильный инструмент для правки</strong> — редактор элементов и комментарии справляются с мелкими правками без полной пересборки.</li>\n<li><strong>Сохраняйте удачные макеты как шаблоны</strong>, чтобы следующий проект стартовал с форой.</li>\n</ul>\n<h2 id=\"faq\">Частые вопросы</h2>\n<p><strong>Open Design бесплатен?</strong>\nДа — это open source под Apache-2.0, и локально он работает бесплатно. Вы платите только за использование модели/API того агента и поставщиков медиа, которых подключаете, и можете пользоваться бесплатными тарифами вроде Gemini.</p>\n<p><strong>Какие кодинг-агенты он поддерживает?</strong>\n21+ агент, включая Claude Code, Codex CLI, Cursor, Gemini CLI и OpenCode. Провайдера вы выбираете в меню в правом верхнем углу.</p>\n<p><strong>Чем он отличается от Claude Design?</strong>\nТо же знакомое ощущение, но open-source, local-first и с заменяемым агентом — вы не привязаны к одной модели или платформе и можете экспортировать или разворачивать проект как угодно.</p>\n<p><strong>Можно ли развернуть, не выходя из приложения?</strong>\nДа — меню «поделиться» разворачивает на Vercel или Cloudflare в один клик (токен доступа поставщика вы предоставляете сами) либо передаёт код в Cursor, VS Code или CLI-агенту.</p>\n<p><strong>Обязательно ли использовать платную модель ради хорошего результата?</strong>\nНет — для большинства лендингов и фронтенд-дизайнов бесплатные модели уже достаточно способны; переключайтесь на платную модель только когда хотите более продвинутый результат.</p>\n<hr>\n<p><em>Это текстовое руководство основано на демо Code A Program. Посмотрите полное видео выше и <a href=\"https://www.youtube.com/watch?v=2AdKzkQyKkg\">подпишитесь на Code A Program</a> ради новых практических видео об ИИ-инструментах.</em></p>",
  },
  "es": {
    title: "Open Design: la alternativa open source GRATUITA a Claude Design",
    summary: "Basado en la demo de Code A Program: crea en Open Design una landing page completa para una herramienta de escritura con IA — elige un agente de codificación (aunque sea gratuito), genera el diseño con un prompt, refínalo con ediciones en el lienzo y luego expórtalo o despliégalo con un clic en Vercel o Cloudflare.",
    bodyHtml: "<p>Open Design toma una idea y la convierte en prototipos, sitios web, diapositivas e incluso vídeos HTML — todo ejecutándose en local, en tu propia máquina. En esta demo, Code A Program instala la aplicación de escritorio, conecta un agente de codificación y construye una landing page premium para una herramienta de escritura con IA llamada <em>Draft</em>, para luego refinarla y desplegarla sin salir del espacio de trabajo. Mira el recorrido completo en el <a href=\"https://www.youtube.com/watch?v=2AdKzkQyKkg\">vídeo de Code A Program</a>, o sigue la guía escrita a continuación.</p>\n<p><img src=\"/tutorials/open-design-free-open-source-alternative-code-a-program/01-workspace.webp\" alt=\"El espacio de trabajo de Open Design ejecutándose en local.\">\n<em>Open Design ejecutándose en local: un espacio de trabajo de diseño open source y agent-native que controlas por completo — sin estar atado a un único modelo.</em></p>\n<h2 id=\"what-is-open-design\">¿Qué es Open Design?</h2>\n<p>Open Design es una plataforma de diseño open source y local-first — una alternativa gratuita a Claude Design y Figma. En lugar de atarte a un proveedor de modelos, funciona <strong>sobre el agente de codificación que ya usas</strong>, así que traes tu propio agente y tu propia key.</p>\n<ul>\n<li><strong>Open source, Apache-2.0</strong> — lee cada línea, autohospédalo o simplemente descarga la app de escritorio.</li>\n<li><strong>Se ejecuta en local</strong> — los proyectos viven en tus propias carpetas, en tu máquina, no en la nube de otro.</li>\n<li><strong>Trae tu propio agente</strong> — se admiten más de 21 agentes de codificación, incluidos Claude Code, Codex, Cursor, Gemini, OpenCode y más; tú eliges qué CLI impulsa la generación.</li>\n<li><strong>Más que prototipos</strong> — sitios web, prototipos, decks de diapositivas, generación de imágenes e incluso vídeo HTML, todo desde un solo espacio de trabajo.</li>\n<li><strong>Con todo incluido</strong> — 129 design systems integrados y más de 460 plugins para que nunca empieces con un lienzo en blanco.</li>\n</ul>\n<p>Si has usado Claude Design, la sensación te resultará familiar al instante — Open Design mantiene la misma experiencia serena y luego le añade el modelo que tú elijas.</p>\n<h2 id=\"step-1--choose-your-agent-and-model\">Paso 1 — Elige tu agente y tu modelo</h2>\n<p>Descarga la app de escritorio desde <a href=\"https://open-design.ai/\">open-design.ai</a>, instálala y responde las breves preguntas de incorporación. Eso te deja directamente en la interfaz de chat principal.</p>\n<p>Arriba a la <strong>derecha</strong>, elige tu proveedor de agente de IA. Como proveedores de CLI locales puedes elegir Claude Code, Codex CLI, Gemini CLI (que tiene límites de uso gratuitos), OpenCode y otros. En la demo, Code A Program usa <strong>OpenCode con el modelo GLM 5.2</strong> porque ha sido sólido para el trabajo de front-end — pero lo clave es la flexibilidad: no quedas atado a un único modelo ni plataforma.</p>\n<h2 id=\"step-2--write-your-prompt\">Paso 2 — Escribe tu prompt</h2>\n<p>El chat tiene una opción de <strong>adjuntar archivo</strong> para material de referencia, además de una sección de <strong>plugins</strong>. Open Design incluye más de 460 plugins que cubren ayudantes de build y test, maquetas 3D, marcos de dispositivos móviles y de escritorio y más — así que si necesitas elementos 3D o una carcasa de dispositivo, añades el plugin en lugar de pelearte con el prompt.</p>\n<p><img src=\"/tutorials/open-design-free-open-source-alternative-code-a-program/plugin-library.webp\" alt=\"La biblioteca de plugins de Open Design.\">\n<em>La biblioteca de plugins: más de 460 plugins para construir, testear, maquetas 3D, marcos de dispositivos y más — añade lo que tu diseño necesite.</em></p>\n<p>Ahora pega un brief. El prompt de la demo pide una <strong>landing page premium para un asistente de escritura con IA llamado Draft</strong>, con una paleta contenida de negro pizarra, marfil y naranja eléctrico, un hero editorial audaz con una animación de generación de texto en vivo, un lienzo de escritura interactivo, un flujo de trabajo de tres pasos, una sección de resultados, una tabla de precios de dos niveles, un FAQ y una llamada a la acción final potente — evitando explícitamente tarjetas, degradados, glassmorphism e imágenes genéricas de robots.</p>\n<p>Hay una palanca más que conviene conocer: puedes basar un diseño en un <strong>design system popular</strong> de marcas como Apple, Airbnb, BMW, IBM o Spotify. Code A Program lo omite en este recorrido, pero ahí está cuando quieras acertar con un look concreto.</p>\n<h2 id=\"step-3--watch-it-build-and-self-check\">Paso 3 — Míralo construir y autoverificarse</h2>\n<p>Envía el prompt y Open Design empieza a preparar el proyecto. Al cabo de un minuto aproximadamente puede hacer algunas <strong>preguntas de seguimiento</strong> — respóndelas para obtener mejores resultados, o pulsa <strong>omitir todo</strong> y déjalo continuar.</p>\n<p>En la demo, la landing page en sí se termina en unos <strong>seis minutos</strong>. Después Open Design dedica el tiempo restante a ejecutar <strong>autoverificaciones</strong> — verificando la estructura, revisando el diseño, comprobando animaciones y corrigiendo pequeños problemas antes de marcar el build como completo. Cuando termina, haz clic en el <strong>icono de presentación</strong> para abrir el sitio en una pestaña nueva.</p>\n<p><img src=\"/tutorials/open-design-free-open-source-alternative-code-a-program/generated-prototype.webp\" alt=\"Una landing page generada, previsualizada en Open Design.\">\n<em>El resultado generado: un hero editorial con animación de tecleo en vivo, flujo de trabajo, resultados, precios, FAQ y pie de página — responsive en tableta y móvil.</em></p>\n<p>El resultado incluye un hero con animación de tecleo de IA, efectos de desplazamiento suaves, una sección de editor interactiva, una franja de flujo de trabajo, una sección de resultados de clientes, precios mensuales/anuales, un FAQ y un pie de página limpio. Cambia a las vistas de <strong>tableta</strong> y <strong>móvil</strong> para confirmar que el diseño responsive aguanta.</p>\n<h2 id=\"step-4--refine-with-the-on-canvas-toolbar\">Paso 4 — Refina con la barra de herramientas del lienzo</h2>\n<p>La barra de herramientas de la derecha es donde pules sin quemar tokens en cambios triviales:</p>\n<ul>\n<li><strong>Screenshot</strong> — captura una imagen del sitio.</li>\n<li><strong>Comment</strong> — selecciona cualquier elemento (por ejemplo, el titular del hero) y describe un cambio, como recolorear una palabra al tema naranja. Agrupa varios comentarios y envíalos de una vez, o manda uno directo al chat.</li>\n<li><strong>Marker</strong> — resalta cualquier área de la página y compártela con el agente.</li>\n<li><strong>Element edit</strong> — cambia directamente tipografías, ancho, colores y más en un elemento seleccionado, para que los ajustes sencillos nunca necesiten una regeneración completa.</li>\n</ul>\n<p>También tienes controles de zoom y una vista de todos los comentarios abiertos. En la demo, el texto «actually» se recolorea a naranja allí mismo, en la barra de herramientas.</p>\n<h2 id=\"step-5--export-and-deploy\">Paso 5 — Exporta y despliega</h2>\n<p>Encima de la barra de herramientas está la opción de <strong>descargar</strong> — exporta el proyecto como <strong>PDF, imagen, ZIP o HTML</strong>. También está <strong>guardar como plantilla</strong>, para reutilizar este diseño como punto de partida de futuros proyectos.</p>\n<p>El menú <strong>compartir</strong> es la parte interesante. Desde ahí puedes:</p>\n<ul>\n<li><strong>desplegar en Vercel</strong> con un clic — conecta tu cuenta de Vercel con un token de acceso y pulsa desplegar.</li>\n<li><strong>desplegar en Cloudflare</strong> del mismo modo.</li>\n<li><strong>abrir en un editor</strong> como Cursor o VS Code, o en herramientas CLI como Gemini CLI, Codex y Claude Code. Open Design te entrega el HTML generado junto con su carpeta Skills, para que conviertas el diseño en un proyecto Next.js — o en el framework que prefieras.</li>\n</ul>\n<p>En <strong>ajustes</strong> puedes añadir reglas globales (por ejemplo, «usar siempre TypeScript»), guardar memorias útiles como la función de memoria de Claude y configurar <strong>proveedores de medios</strong> — una key de ElevenLabs para voz y sonido, además de Nano Banana, OpenAI o OpenRouter para la generación de imágenes. También puedes añadir skills (hay un skill agent-browser para automatizar tareas del navegador, y varios skills de front-end), conectar servidores MCP y cambiar la ubicación por defecto de los proyectos.</p>\n<h2 id=\"tips-for-getting-more-out-of-it\">Consejos para sacarle más partido</h2>\n<ul>\n<li><strong>Los modelos gratuitos bastan para empezar.</strong> Todo el sitio de la demo se generó con un nivel gratuito de Gemini y aun así luce estupendo; recurre a un modelo de pago cuando quieras mayor calidad en trabajo real.</li>\n<li><strong>Añade plugins antes de promptear</strong> cuando sepas que vas a necesitar maquetas 3D o marcos de dispositivos.</li>\n<li><strong>Usa la herramienta adecuada para el cambio</strong> — el editor de elementos y los comentarios resuelven pequeños ajustes sin una reconstrucción completa.</li>\n<li><strong>Guarda los diseños que funcionen como plantillas</strong> para que tu próximo proyecto arranque con ventaja.</li>\n</ul>\n<h2 id=\"faq\">Preguntas frecuentes</h2>\n<p><strong>¿Open Design es gratis?</strong>\nSí — es open source bajo Apache-2.0 y se ejecuta en local de forma gratuita. Solo pagas por el uso de modelo/API del agente y de los proveedores de medios que conectes, y puedes usar niveles gratuitos como el de Gemini.</p>\n<p><strong>¿Qué agentes de codificación admite?</strong>\nMás de 21 agentes, incluidos Claude Code, Codex CLI, Cursor, Gemini CLI y OpenCode. Eliges el proveedor en el menú de arriba a la derecha.</p>\n<p><strong>¿En qué se diferencia de Claude Design?</strong>\nLa misma sensación familiar, pero open source, local-first y con agente intercambiable — no quedas atado a un modelo ni a una plataforma, y puedes exportar o desplegar tu proyecto como quieras.</p>\n<p><strong>¿Puedo desplegar sin salir de la app?</strong>\nSí — el menú compartir despliega en Vercel o Cloudflare con un clic (tú aportas el token de acceso del proveedor), o entrega el código a Cursor, VS Code o un agente CLI.</p>\n<p><strong>¿Tengo que usar un modelo de pago para buenos resultados?</strong>\nNo — para la mayoría de landing pages y diseños de front-end, los modelos gratuitos ya son lo bastante capaces; cambia a un modelo de pago solo cuando quieras resultados más avanzados.</p>\n<hr>\n<p><em>Esta guía escrita se basa en la demo de Code A Program. Mira el vídeo completo arriba y <a href=\"https://www.youtube.com/watch?v=2AdKzkQyKkg\">suscríbete a Code A Program</a> para más vídeos prácticos sobre herramientas de IA.</em></p>",
  },
  "pt-br": {
    title: "Open Design: a alternativa open source GRATUITA ao Claude Design",
    summary: "Baseado na demo do Code A Program: monte no Open Design uma landing page completa para uma ferramenta de escrita com IA — escolha um agente de código (mesmo um gratuito), gere o design por prompt, refine com edições no canvas e depois exporte ou faça deploy com um clique na Vercel ou na Cloudflare.",
    bodyHtml: "<p>O Open Design pega uma ideia e a transforma em protótipos, sites, slides e até vídeos HTML — tudo rodando localmente na sua própria máquina. Nesta demo, o Code A Program instala o app de desktop, conecta um agente de código e monta uma landing page premium para uma ferramenta de escrita com IA chamada <em>Draft</em>, e então a refina e faz o deploy sem sair do espaço de trabalho. Assista ao processo completo no <a href=\"https://www.youtube.com/watch?v=2AdKzkQyKkg\">vídeo do Code A Program</a>, ou siga o guia escrito abaixo.</p>\n<p><img src=\"/tutorials/open-design-free-open-source-alternative-code-a-program/01-workspace.webp\" alt=\"O espaço de trabalho do Open Design rodando localmente.\">\n<em>Open Design rodando localmente: um espaço de trabalho de design open source e agent-native que você controla por completo — sem estar preso a um único modelo.</em></p>\n<h2 id=\"what-is-open-design\">O que é o Open Design?</h2>\n<p>O Open Design é uma plataforma de design open source e local-first — uma alternativa gratuita ao Claude Design e ao Figma. Em vez de prender você a um provedor de modelo, ele roda <strong>sobre o agente de código que você já usa</strong>, então você traz o seu próprio agente e a sua própria key.</p>\n<ul>\n<li><strong>Open source, Apache-2.0</strong> — leia cada linha, faça self-host ou apenas baixe o app de desktop.</li>\n<li><strong>Roda localmente</strong> — os projetos ficam nas suas próprias pastas, na sua máquina, não na nuvem de outra pessoa.</li>\n<li><strong>Traga o seu próprio agente</strong> — mais de 21 agentes de código são suportados, incluindo Claude Code, Codex, Cursor, Gemini, OpenCode e outros; você escolhe qual CLI conduz a geração.</li>\n<li><strong>Mais do que protótipos</strong> — sites, protótipos, decks de slides, geração de imagens e até vídeo HTML, tudo a partir de um só espaço de trabalho.</li>\n<li><strong>Já vem completo</strong> — 129 design systems integrados e mais de 460 plugins para você nunca começar de um canvas em branco.</li>\n</ul>\n<p>Se você já usou o Claude Design, a sensação será familiar na hora — o Open Design mantém a mesma experiência tranquila e então acrescenta por cima o modelo da sua escolha.</p>\n<h2 id=\"step-1--choose-your-agent-and-model\">Passo 1 — Escolha seu agente e seu modelo</h2>\n<p>Baixe o app de desktop em <a href=\"https://open-design.ai/\">open-design.ai</a>, instale-o e responda às breves perguntas de onboarding. Isso já leva você direto para a interface principal de chat.</p>\n<p>No <strong>canto superior direito</strong>, escolha o provedor do seu agente de IA. Como provedores de CLI locais, você pode escolher Claude Code, Codex CLI, Gemini CLI (que tem limites de uso gratuitos), OpenCode e outros. Na demo, o Code A Program usa <strong>OpenCode com o modelo GLM 5.2</strong> porque tem sido forte em trabalho de front-end — mas o ponto-chave é a flexibilidade: você não fica preso a um único modelo ou plataforma.</p>\n<h2 id=\"step-2--write-your-prompt\">Passo 2 — Escreva seu prompt</h2>\n<p>O chat tem uma opção de <strong>anexar arquivo</strong> para material de referência, além de uma seção de <strong>plugins</strong>. O Open Design vem com mais de 460 plugins que cobrem auxiliares de build e teste, mockups 3D, molduras de dispositivos móveis e desktop e muito mais — então, se você precisar de elementos 3D ou de uma carcaça de dispositivo, adiciona o plugin em vez de brigar com o prompt.</p>\n<p><img src=\"/tutorials/open-design-free-open-source-alternative-code-a-program/plugin-library.webp\" alt=\"A biblioteca de plugins do Open Design.\">\n<em>A biblioteca de plugins: mais de 460 plugins para construir, testar, mockups 3D, molduras de dispositivos e mais — adicione o que o seu design precisar.</em></p>\n<p>Agora cole um brief. O prompt da demo pede uma <strong>landing page premium para um assistente de escrita com IA chamado Draft</strong>, com uma paleta contida de preto ardósia, marfim e laranja elétrico, um hero editorial marcante com uma animação de geração de texto ao vivo, um canvas de escrita interativo, um fluxo de trabalho de três etapas, uma seção de resultados, uma tabela de preços de dois níveis, um FAQ e uma chamada para ação final forte — ao mesmo tempo em que evita explicitamente cards, gradientes, glassmorphism e imagens genéricas de robôs.</p>\n<p>Há mais uma alavanca que vale conhecer: você pode basear um design em um <strong>design system popular</strong> de marcas como Apple, Airbnb, BMW, IBM ou Spotify. O Code A Program pula isso nesta execução, mas está ali quando você quiser acertar um visual específico.</p>\n<h2 id=\"step-3--watch-it-build-and-self-check\">Passo 3 — Veja ele construir e se autoverificar</h2>\n<p>Envie o prompt e o Open Design começa a preparar o projeto. Depois de cerca de um minuto, ele pode fazer algumas <strong>perguntas de acompanhamento</strong> — responda-as para resultados melhores, ou clique em <strong>pular tudo</strong> e deixe-o continuar.</p>\n<p>Na demo, a landing page em si fica pronta em cerca de <strong>seis minutos</strong>. Em seguida, o Open Design gasta o tempo restante rodando <strong>autoverificações</strong> — conferindo a estrutura, revisando o layout, checando animações e corrigindo pequenos problemas antes de marcar o build como concluído. Quando termina, clique no <strong>ícone de apresentação</strong> para abrir o site em uma nova aba.</p>\n<p><img src=\"/tutorials/open-design-free-open-source-alternative-code-a-program/generated-prototype.webp\" alt=\"Uma landing page gerada, pré-visualizada no Open Design.\">\n<em>O resultado gerado: um hero editorial com animação de digitação ao vivo, fluxo de trabalho, resultados, preços, FAQ e rodapé — responsivo em tablet e mobile.</em></p>\n<p>O resultado traz um hero com animação de digitação por IA, efeitos de rolagem suaves, uma seção de editor interativa, uma faixa de fluxo de trabalho, uma seção de resultados de clientes, preços mensais/anuais, um FAQ e um rodapé limpo. Alterne para as visualizações de <strong>tablet</strong> e <strong>mobile</strong> para confirmar que o design responsivo se sustenta.</p>\n<h2 id=\"step-4--refine-with-the-on-canvas-toolbar\">Passo 4 — Refine com a barra de ferramentas do canvas</h2>\n<p>A barra de ferramentas da direita é onde você lapida sem queimar tokens em mudanças triviais:</p>\n<ul>\n<li><strong>Screenshot</strong> — capture uma imagem do site.</li>\n<li><strong>Comment</strong> — selecione qualquer elemento (por exemplo, o título do hero) e descreva uma mudança, como recolorir uma palavra para o tema laranja. Junte vários comentários e envie de uma vez, ou mande um direto para o chat.</li>\n<li><strong>Marker</strong> — destaque qualquer área da página e compartilhe com o agente.</li>\n<li><strong>Element edit</strong> — altere diretamente fontes, largura, cores e mais em um elemento selecionado, para que ajustes simples nunca precisem de uma regeneração completa.</li>\n</ul>\n<p>Você também tem controles de zoom e uma visão de todos os comentários abertos. Na demo, o texto “actually” é recolorido para laranja bem ali, na barra de ferramentas.</p>\n<h2 id=\"step-5--export-and-deploy\">Passo 5 — Exporte e faça deploy</h2>\n<p>Acima da barra de ferramentas está a opção de <strong>download</strong> — exporte o projeto como <strong>PDF, imagem, ZIP ou HTML</strong>. Há também <strong>salvar como template</strong>, para reutilizar este design como ponto de partida de projetos futuros.</p>\n<p>O menu <strong>compartilhar</strong> é a parte interessante. A partir dele, você pode:</p>\n<ul>\n<li><strong>fazer deploy na Vercel</strong> com um clique — conecte sua conta da Vercel com um token de acesso e clique em deploy.</li>\n<li><strong>fazer deploy na Cloudflare</strong> do mesmo jeito.</li>\n<li><strong>abrir em um editor</strong> como Cursor ou VS Code, ou em ferramentas CLI como Gemini CLI, Codex e Claude Code. O Open Design entrega o HTML gerado junto com a pasta Skills dele, para que você converta o design em um projeto Next.js — ou em qualquer framework que preferir.</li>\n</ul>\n<p>Em <strong>configurações</strong>, você pode adicionar regras globais (por exemplo, “sempre usar TypeScript”), guardar memórias úteis como no recurso de memória do Claude e configurar <strong>provedores de mídia</strong> — uma key da ElevenLabs para voz e som, além de Nano Banana, OpenAI ou OpenRouter para a geração de imagens. Você também pode adicionar skills (há um skill agent-browser para automatizar tarefas de navegador, e vários skills de front-end), conectar servidores MCP e mudar o local padrão dos projetos.</p>\n<h2 id=\"tips-for-getting-more-out-of-it\">Dicas para tirar mais proveito</h2>\n<ul>\n<li><strong>Modelos gratuitos bastam para começar.</strong> Todo o site da demo foi gerado com um nível gratuito do Gemini e ainda assim fica ótimo; recorra a um modelo pago quando quiser mais qualidade em trabalho real.</li>\n<li><strong>Adicione plugins antes de promptar</strong> quando souber que vai precisar de mockups 3D ou molduras de dispositivos.</li>\n<li><strong>Use a ferramenta certa para a mudança</strong> — o editor de elementos e os comentários dão conta de pequenos ajustes sem uma reconstrução completa.</li>\n<li><strong>Salve os layouts que deram certo como templates</strong> para que seu próximo projeto comece na frente.</li>\n</ul>\n<h2 id=\"faq\">Perguntas frequentes</h2>\n<p><strong>O Open Design é gratuito?</strong>\nSim — é open source sob a Apache-2.0 e roda localmente de graça. Você só paga pelo uso de modelo/API de qualquer agente e provedores de mídia que conectar, e pode usar níveis gratuitos como o do Gemini.</p>\n<p><strong>Quais agentes de código ele suporta?</strong>\nMais de 21 agentes, incluindo Claude Code, Codex CLI, Cursor, Gemini CLI e OpenCode. Você escolhe o provedor no menu do canto superior direito.</p>\n<p><strong>Em que ele difere do Claude Design?</strong>\nA mesma sensação familiar, mas open source, local-first e com agente plugável — você não fica preso a um modelo ou plataforma, e pode exportar ou fazer deploy do seu projeto do jeito que quiser.</p>\n<p><strong>Consigo fazer deploy sem sair do app?</strong>\nSim — o menu compartilhar faz deploy na Vercel ou na Cloudflare com um clique (você fornece o token de acesso do provedor), ou entrega o código ao Cursor, ao VS Code ou a um agente CLI.</p>\n<p><strong>Preciso usar um modelo pago para bons resultados?</strong>\nNão — para a maioria das landing pages e designs de front-end, os modelos gratuitos já são capazes o bastante; mude para um modelo pago só quando quiser resultados mais avançados.</p>\n<hr>\n<p><em>Este guia escrito é baseado na demo do Code A Program. Assista ao vídeo completo acima e <a href=\"https://www.youtube.com/watch?v=2AdKzkQyKkg\">inscreva-se no Code A Program</a> para mais vídeos práticos sobre ferramentas de IA.</em></p>",
  },
  "it": {
    title: "Open Design: l’alternativa open source GRATUITA a Claude Design",
    summary: "Basato sulla demo di Code A Program: costruisci in Open Design una landing page completa per uno strumento di scrittura con IA — scegli un agente di coding (anche gratuito), genera il design con un prompt, rifiniscilo con modifiche sul canvas e poi esporta o fai il deploy con un clic su Vercel o Cloudflare.",
    bodyHtml: "<p>Open Design prende un’idea e la trasforma in prototipi, siti web, slide e persino video HTML — il tutto in esecuzione in locale, sulla tua macchina. In questa demo, Code A Program installa l’app desktop, collega un agente di coding e costruisce una landing page premium per uno strumento di scrittura con IA chiamato <em>Draft</em>, per poi rifinirla e distribuirla senza mai lasciare l’area di lavoro. Guarda l’intero percorso nel <a href=\"https://www.youtube.com/watch?v=2AdKzkQyKkg\">video di Code A Program</a>, oppure segui la guida scritta qui sotto.</p>\n<p><img src=\"/tutorials/open-design-free-open-source-alternative-code-a-program/01-workspace.webp\" alt=\"L’area di lavoro di Open Design in esecuzione in locale.\">\n<em>Open Design in esecuzione in locale: un’area di lavoro di design open source e agent-native che controlli completamente — non vincolata a un singolo modello.</em></p>\n<h2 id=\"what-is-open-design\">Che cos’è Open Design?</h2>\n<p>Open Design è una piattaforma di design open source e local-first — un’alternativa gratuita a Claude Design e Figma. Invece di legarti a un fornitore di modelli, gira <strong>sopra l’agente di coding che già usi</strong>, così porti il tuo agente e la tua key.</p>\n<ul>\n<li><strong>Open source, Apache-2.0</strong> — leggi ogni riga, fai self-host oppure scarica semplicemente l’app desktop.</li>\n<li><strong>Gira in locale</strong> — i progetti vivono nelle tue cartelle, sulla tua macchina, non nel cloud di qualcun altro.</li>\n<li><strong>Porta il tuo agente</strong> — sono supportati oltre 21 agenti di coding, tra cui Claude Code, Codex, Cursor, Gemini, OpenCode e altri; scegli tu quale CLI guida la generazione.</li>\n<li><strong>Più che prototipi</strong> — siti web, prototipi, deck di slide, generazione di immagini e persino video HTML, tutto da un’unica area di lavoro.</li>\n<li><strong>Tutto incluso</strong> — 129 design system integrati e oltre 460 plugin, così non parti mai da un canvas vuoto.</li>\n</ul>\n<p>Se hai usato Claude Design, la sensazione ti sarà subito familiare — Open Design mantiene la stessa esperienza pacata e poi ci aggiunge sopra il modello che scegli tu.</p>\n<h2 id=\"step-1--choose-your-agent-and-model\">Passo 1 — Scegli il tuo agente e il tuo modello</h2>\n<p>Scarica l’app desktop da <a href=\"https://open-design.ai/\">open-design.ai</a>, installala e rispondi alle brevi domande di onboarding. Questo ti porta dritto nell’interfaccia di chat principale.</p>\n<p>In <strong>alto a destra</strong>, scegli il tuo fornitore di agente IA. Come fornitori di CLI locali puoi scegliere Claude Code, Codex CLI, Gemini CLI (che ha limiti di utilizzo gratuiti), OpenCode e altri. Nella demo, Code A Program usa <strong>OpenCode con il modello GLM 5.2</strong> perché si è dimostrato valido per il lavoro di front-end — ma il punto chiave è la flessibilità: non resti vincolato a un solo modello o a una sola piattaforma.</p>\n<h2 id=\"step-2--write-your-prompt\">Passo 2 — Scrivi il tuo prompt</h2>\n<p>La chat ha un’opzione <strong>allega file</strong> per il materiale di riferimento, oltre a una sezione <strong>plugin</strong>. Open Design include oltre 460 plugin che coprono helper di build e test, mockup 3D, cornici di dispositivi mobile e desktop e altro — così, se ti servono elementi 3D o una scocca di dispositivo, aggiungi il plugin invece di combattere con il prompt.</p>\n<p><img src=\"/tutorials/open-design-free-open-source-alternative-code-a-program/plugin-library.webp\" alt=\"La libreria di plugin di Open Design.\">\n<em>La libreria di plugin: oltre 460 plugin per costruire, testare, mockup 3D, cornici di dispositivi e altro — aggiungi ciò che serve al tuo design.</em></p>\n<p>Ora incolla un brief. Il prompt della demo chiede una <strong>landing page premium per un assistente di scrittura con IA chiamato Draft</strong>, con una palette sobria di nero ardesia, avorio e arancione elettrico, un hero editoriale deciso con un’animazione di generazione di testo in tempo reale, un canvas di scrittura interattivo, un flusso di lavoro in tre passi, una sezione risultati, una tabella prezzi a due livelli, una FAQ e una potente call to action finale — evitando esplicitamente card, gradienti, glassmorphism e immagini di robot generiche.</p>\n<p>C’è un’altra leva che vale la pena conoscere: puoi basare un design su un <strong>design system popolare</strong> di marchi come Apple, Airbnb, BMW, IBM o Spotify. Code A Program lo salta in questa esecuzione, ma è lì quando vuoi centrare un look preciso.</p>\n<h2 id=\"step-3--watch-it-build-and-self-check\">Passo 3 — Guardalo costruire e autoverificarsi</h2>\n<p>Invia il prompt e Open Design inizia a preparare il progetto. Dopo circa un minuto potrebbe farti alcune <strong>domande di follow-up</strong> — rispondi per risultati migliori, oppure premi <strong>salta tutto</strong> e lascialo continuare.</p>\n<p>Nella demo, la landing page in sé è pronta in circa <strong>sei minuti</strong>. Poi Open Design impiega il tempo rimanente per eseguire le <strong>autoverifiche</strong> — verifica la struttura, rivede il layout, controlla le animazioni e sistema piccoli problemi prima di segnare il build come completato. Quando ha finito, clicca sull’<strong>icona di presentazione</strong> per aprire il sito in una nuova scheda.</p>\n<p><img src=\"/tutorials/open-design-free-open-source-alternative-code-a-program/generated-prototype.webp\" alt=\"Una landing page generata, in anteprima in Open Design.\">\n<em>Il risultato generato: un hero editoriale con animazione di digitazione in tempo reale, flusso di lavoro, risultati, prezzi, FAQ e footer — responsive su tablet e mobile.</em></p>\n<p>Il risultato porta un hero con animazione di digitazione IA, effetti di scroll fluidi, una sezione editor interattiva, una fascia di flusso di lavoro, una sezione risultati clienti, prezzi mensili/annuali, una FAQ e un footer pulito. Passa alle viste <strong>tablet</strong> e <strong>mobile</strong> per confermare che il design responsive regga.</p>\n<h2 id=\"step-4--refine-with-the-on-canvas-toolbar\">Passo 4 — Rifinisci con la barra degli strumenti sul canvas</h2>\n<p>La barra degli strumenti a destra è dove rifinisci senza bruciare token per modifiche banali:</p>\n<ul>\n<li><strong>Screenshot</strong> — cattura un’immagine del sito.</li>\n<li><strong>Comment</strong> — seleziona un qualsiasi elemento (ad esempio il titolo dell’hero) e descrivi una modifica, come ricolorare una parola con il tema arancione. Raggruppa più commenti e inviali in una volta, oppure mandane uno direttamente in chat.</li>\n<li><strong>Marker</strong> — evidenzia una qualsiasi area della pagina e condividila con l’agente.</li>\n<li><strong>Element edit</strong> — cambia direttamente font, larghezza, colori e altro su un elemento selezionato, così i piccoli ritocchi non richiedono mai una rigenerazione completa.</li>\n</ul>\n<p>Hai anche i controlli di zoom e una vista di tutti i commenti aperti. Nella demo, il testo «actually» viene ricolorato in arancione proprio lì, nella barra degli strumenti.</p>\n<h2 id=\"step-5--export-and-deploy\">Passo 5 — Esporta e fai il deploy</h2>\n<p>Sopra la barra degli strumenti c’è l’opzione <strong>scarica</strong> — esporta il progetto come <strong>PDF, immagine, ZIP o HTML</strong>. C’è anche <strong>salva come template</strong>, così puoi riutilizzare questo design come punto di partenza per progetti futuri.</p>\n<p>Il menu <strong>condividi</strong> è la parte interessante. Da lì puoi:</p>\n<ul>\n<li><strong>fare il deploy su Vercel</strong> con un clic — collega il tuo account Vercel con un token di accesso e premi deploy.</li>\n<li><strong>fare il deploy su Cloudflare</strong> allo stesso modo.</li>\n<li><strong>aprire in un editor</strong> come Cursor o VS Code, oppure in strumenti CLI come Gemini CLI, Codex e Claude Code. Open Design ti consegna l’HTML generato insieme alla sua cartella Skills, così puoi convertire il design in un progetto Next.js — o in qualsiasi framework tu preferisca.</li>\n</ul>\n<p>In <strong>impostazioni</strong> puoi aggiungere regole globali (ad esempio «usa sempre TypeScript»), salvare memorie utili come la funzione di memoria di Claude e configurare i <strong>fornitori di media</strong> — una key ElevenLabs per voce e suono, oltre a Nano Banana, OpenAI o OpenRouter per la generazione di immagini. Puoi anche aggiungere skill (c’è uno skill agent-browser per automatizzare le attività del browser, e diversi skill front-end), collegare server MCP e cambiare la posizione predefinita dei progetti.</p>\n<h2 id=\"tips-for-getting-more-out-of-it\">Consigli per ottenere di più</h2>\n<ul>\n<li><strong>I modelli gratuiti bastano per iniziare.</strong> L’intero sito della demo è stato generato con un piano gratuito di Gemini e ha comunque un ottimo aspetto; passa a un modello a pagamento quando vuoi una qualità più alta per il lavoro vero.</li>\n<li><strong>Aggiungi i plugin prima di fare il prompt</strong> quando sai che ti serviranno mockup 3D o cornici di dispositivi.</li>\n<li><strong>Usa lo strumento giusto per la modifica</strong> — l’editor degli elementi e i commenti gestiscono i piccoli ritocchi senza una ricostruzione completa.</li>\n<li><strong>Salva i layout riusciti come template</strong> così il tuo prossimo progetto parte in vantaggio.</li>\n</ul>\n<h2 id=\"faq\">Domande frequenti</h2>\n<p><strong>Open Design è gratuito?</strong>\nSì — è open source sotto Apache-2.0 e in locale gira gratuitamente. Paghi solo per l’uso di modello/API dell’agente e dei fornitori di media che colleghi, e puoi usare piani gratuiti come quello di Gemini.</p>\n<p><strong>Quali agenti di coding supporta?</strong>\nOltre 21 agenti, tra cui Claude Code, Codex CLI, Cursor, Gemini CLI e OpenCode. Il fornitore lo scegli dal menu in alto a destra.</p>\n<p><strong>In cosa differisce da Claude Design?</strong>\nLa stessa sensazione familiare, ma open source, local-first e con agente sostituibile — non resti vincolato a un modello o a una piattaforma, e puoi esportare o distribuire il tuo progetto come preferisci.</p>\n<p><strong>Posso fare il deploy senza lasciare l’app?</strong>\nSì — il menu condividi distribuisce su Vercel o Cloudflare con un clic (il token di accesso del fornitore lo fornisci tu), oppure consegna il codice a Cursor, VS Code o a un agente CLI.</p>\n<p><strong>Devo usare un modello a pagamento per buoni risultati?</strong>\nNo — per la maggior parte delle landing page e dei design front-end, i modelli gratuiti sono già abbastanza capaci; passa a un modello a pagamento solo quando vuoi risultati più avanzati.</p>\n<hr>\n<p><em>Questa guida scritta è basata sulla demo di Code A Program. Guarda il video completo qui sopra e <a href=\"https://www.youtube.com/watch?v=2AdKzkQyKkg\">iscriviti a Code A Program</a> per altri video pratici sugli strumenti IA.</em></p>",
  },
  "tr": {
    title: "Open Design: ÜCRETSIZ açık kaynaklı Claude Design alternatifi",
    summary: "Code A Program’ın demosuna dayanır: Open Design’da bir AI yazım aracı için eksiksiz bir açılış sayfası kur — bir kodlama ajanı seç (ücretsiz olan bile olur), tasarımı bir komutla üret, tuval üzerindeki düzenlemelerle ince ayar yap, sonra dışa aktar ya da tek tıkla Vercel veya Cloudflare’e dağıt.",
    bodyHtml: "<p>Open Design bir fikri alır ve onu prototiplere, web sitelerine, slaytlara ve hatta HTML videolara dönüştürür — hepsi kendi makinende yerel olarak çalışır. Bu demoda Code A Program masaüstü uygulamasını kurar, bir kodlama ajanı bağlar ve <em>Draft</em> adlı bir AI yazım aracı için üst düzey bir açılış sayfası inşa eder, ardından çalışma alanından hiç çıkmadan onu ince ayarlar ve dağıtır. Tüm akışı <a href=\"https://www.youtube.com/watch?v=2AdKzkQyKkg\">Code A Program’ın videosunda</a> izle ya da aşağıdaki yazılı rehberi takip et.</p>\n<p><img src=\"/tutorials/open-design-free-open-source-alternative-code-a-program/01-workspace.webp\" alt=\"Yerel olarak çalışan Open Design çalışma alanı.\">\n<em>Yerel çalışan Open Design: tamamen senin kontrolünde olan açık kaynaklı, ajan yerlisi (agent-native) bir tasarım çalışma alanı — tek bir modele kilitli değil.</em></p>\n<h2 id=\"what-is-open-design\">Open Design nedir?</h2>\n<p>Open Design açık kaynaklı, yerel öncelikli (local-first) bir tasarım platformudur — Claude Design ve Figma’ya ücretsiz bir alternatif. Seni tek bir model sağlayıcısına bağlamak yerine, <strong>zaten kullandığın kodlama ajanının üzerinde</strong> çalışır; yani kendi ajanını ve kendi key’ini getirirsin.</p>\n<ul>\n<li><strong>Açık kaynak, Apache-2.0</strong> — her satırı oku, kendin barındır ya da sadece masaüstü uygulamasını indir.</li>\n<li><strong>Yerelde çalışır</strong> — projeler bir başkasının bulutunda değil, kendi makinendeki kendi klasörlerinde durur.</li>\n<li><strong>Kendi ajanını getir</strong> — Claude Code, Codex, Cursor, Gemini, OpenCode ve daha fazlası dahil 21+ kodlama ajanı desteklenir; üretimi hangi CLI’nın sürdüğünü sen seçersin.</li>\n<li><strong>Prototiplerden fazlası</strong> — web siteleri, prototipler, slayt desteleri, görsel üretimi ve hatta HTML video, hepsi tek bir çalışma alanından.</li>\n<li><strong>Her şey hazır gelir</strong> — 129 yerleşik tasarım sistemi ve 460+ eklenti, böylece asla boş bir tuvalden başlamazsın.</li>\n</ul>\n<p>Claude Design kullandıysan, his anında tanıdık gelecek — Open Design aynı sakin deneyimi korur, sonra üzerine senin seçtiğin modeli ekler.</p>\n<h2 id=\"step-1--choose-your-agent-and-model\">Adım 1 — Ajanını ve modelini seç</h2>\n<p><a href=\"https://open-design.ai/\">open-design.ai</a> adresinden masaüstü uygulamasını indir, kur ve kısa tanışma sorularını yanıtla. Bu seni doğrudan ana sohbet arayüzüne bırakır.</p>\n<p><strong>Sağ üstte</strong> AI ajan sağlayıcını seç. Yerel CLI sağlayıcıları olarak Claude Code, Codex CLI, Gemini CLI (ücretsiz kullanım limitleri var), OpenCode ve diğerlerini seçebilirsin. Demoda Code A Program <strong>GLM 5.2 modeliyle OpenCode</strong> kullanıyor çünkü ön yüz işlerinde güçlü olmuştur — ama asıl önemli olan esneklik: tek bir modele ya da platforma kilitli değilsin.</p>\n<h2 id=\"step-2--write-your-prompt\">Adım 2 — Komutunu yaz</h2>\n<p>Sohbette referans materyal için bir <strong>dosya ekle</strong> seçeneği ve bir <strong>eklenti</strong> bölümü var. Open Design; build ve test yardımcıları, 3D maketler, mobil ve masaüstü cihaz çerçeveleri ve daha fazlasını kapsayan 460+ eklentiyle gelir — yani 3D öğeler veya bir cihaz kabuğu gerekiyorsa, komutla boğuşmak yerine eklentiyi eklersin.</p>\n<p><img src=\"/tutorials/open-design-free-open-source-alternative-code-a-program/plugin-library.webp\" alt=\"Open Design eklenti kütüphanesi.\">\n<em>Eklenti kütüphanesi: inşa, test, 3D maket, cihaz çerçeveleri ve daha fazlası için 460+ eklenti — tasarımının ihtiyacı olanı ekle.</em></p>\n<p>Şimdi bir brief yapıştır. Demo komutu, <strong>Draft adlı bir AI yazım asistanı için üst düzey bir açılış sayfası</strong> istiyor; ölçülü bir arduvaz siyahı, fildişi ve elektrik turuncusu paleti, canlı bir metin üretimi animasyonu olan cesur editöryel bir hero, etkileşimli bir yazım tuvali, üç adımlı bir iş akışı, bir sonuçlar bölümü, iki kademeli bir fiyat tablosu, bir SSS ve güçlü bir son harekete geçirici mesajla — aynı zamanda kartlardan, gradyanlardan, glassmorphism’den ve basmakalıp robot görsellerinden açıkça kaçınarak.</p>\n<p>Bilmeye değer bir kaldıraç daha var: bir tasarımı Apple, Airbnb, BMW, IBM veya Spotify gibi markaların <strong>popüler bir tasarım sistemi</strong> üzerine kurabilirsin. Code A Program bu çalıştırmada onu atlıyor, ama belirli bir görünümü yakalamak istediğinde orada.</p>\n<h2 id=\"step-3--watch-it-build-and-self-check\">Adım 3 — İnşa etmesini ve kendini denetlemesini izle</h2>\n<p>Komutu gönder, Open Design projeyi hazırlamaya başlasın. Yaklaşık bir dakika sonra birkaç <strong>takip sorusu</strong> sorabilir — daha iyi sonuçlar için yanıtla ya da <strong>tümünü atla</strong>’ya basıp devam etmesine izin ver.</p>\n<p>Demoda açılış sayfasının kendisi yaklaşık <strong>altı dakikada</strong> biter. Ardından Open Design kalan süreyi <strong>kendi denetimlerini</strong> yaparak geçirir — yapıyı doğrular, düzeni gözden geçirir, animasyonları kontrol eder ve build’i tamamlandı olarak işaretlemeden önce küçük sorunları düzeltir. Bittiğinde, siteyi yeni bir sekmede açmak için <strong>sunum simgesine</strong> tıkla.</p>\n<p><img src=\"/tutorials/open-design-free-open-source-alternative-code-a-program/generated-prototype.webp\" alt=\"Open Design’da önizlenen, üretilmiş bir açılış sayfası.\">\n<em>Üretilen sonuç: canlı yazım animasyonlu editöryel bir hero, iş akışı, sonuçlar, fiyatlandırma, SSS ve altbilgi — tablet ve mobilde duyarlı.</em></p>\n<p>Sonuç; AI yazım animasyonlu bir hero, akıcı kaydırma efektleri, etkileşimli bir editör bölümü, bir iş akışı şeridi, bir müşteri sonuçları bölümü, aylık/yıllık fiyatlandırma, bir SSS ve temiz bir altbilgi taşır. Duyarlı tasarımın ayakta kaldığını doğrulamak için <strong>tablet</strong> ve <strong>mobil</strong> görünümlerine geç.</p>\n<h2 id=\"step-4--refine-with-the-on-canvas-toolbar\">Adım 4 — Tuval üzerindeki araç çubuğuyla ince ayar yap</h2>\n<p>Sağdaki araç çubuğu, önemsiz değişiklikler için token yakmadan cilaladığın yerdir:</p>\n<ul>\n<li><strong>Screenshot</strong> — sitenin bir görüntüsünü al.</li>\n<li><strong>Comment</strong> — herhangi bir öğeyi seç (örneğin hero başlığını) ve bir değişikliği tarif et, örneğin bir kelimeyi turuncu temaya boyamak gibi. Birkaç yorumu toplayıp bir kerede gönder ya da birini doğrudan sohbete yolla.</li>\n<li><strong>Marker</strong> — sayfanın herhangi bir alanını vurgula ve ajanla paylaş.</li>\n<li><strong>Element edit</strong> — seçili bir öğede yazı tiplerini, genişliği, renkleri ve daha fazlasını doğrudan değiştir; böylece basit ince ayarlar asla tam bir yeniden üretim gerektirmez.</li>\n</ul>\n<p>Ayrıca yakınlaştırma kontrolleri ve açık tüm yorumların bir görünümü de sende. Demoda o “actually” metni, tam orada, araç çubuğunda turuncuya boyanıyor.</p>\n<h2 id=\"step-5--export-and-deploy\">Adım 5 — Dışa aktar ve dağıt</h2>\n<p>Araç çubuğunun üstünde <strong>indirme</strong> seçeneği var — projeyi <strong>PDF, görüntü, ZIP veya HTML</strong> olarak dışa aktar. Bir de <strong>şablon olarak kaydet</strong> var; böylece bu tasarımı gelecekteki projeler için bir başlangıç noktası olarak yeniden kullanabilirsin.</p>\n<p>İlginç kısım <strong>paylaş</strong> menüsü. Oradan şunları yapabilirsin:</p>\n<ul>\n<li>tek tıkla <strong>Vercel’e dağıt</strong> — Vercel hesabını bir erişim token’ıyla bağla ve dağıt’a bas.</li>\n<li>aynı şekilde <strong>Cloudflare’e dağıt</strong>.</li>\n<li>Cursor veya VS Code gibi bir <strong>editörde aç</strong>, ya da Gemini CLI, Codex ve Claude Code gibi CLI araçlarında aç. Open Design üretilen HTML’i, Skills klasörüyle birlikte sana devreder; böylece tasarımı bir Next.js projesine — ya da istediğin herhangi bir framework’e — dönüştürebilirsin.</li>\n</ul>\n<p><strong>Ayarlar</strong> altında global kurallar ekleyebilir (örneğin “her zaman TypeScript kullan”), Claude’un bellek özelliği gibi işe yarar bellekler saklayabilir ve <strong>medya sağlayıcılarını</strong> yapılandırabilirsin — ses için bir ElevenLabs key’i, ayrıca görsel üretimi için Nano Banana, OpenAI veya OpenRouter. Ayrıca beceriler ekleyebilir (tarayıcı görevlerini otomatikleştiren bir agent-browser becerisi ve birkaç ön yüz becerisi var), MCP sunucuları bağlayabilir ve varsayılan proje konumunu değiştirebilirsin.</p>\n<h2 id=\"tips-for-getting-more-out-of-it\">Daha fazlasını almak için ipuçları</h2>\n<ul>\n<li><strong>Başlamak için ücretsiz modeller yeter.</strong> Tüm demo sitesi ücretsiz bir Gemini kademesiyle üretildi ve yine de harika görünüyor; gerçek işte daha yüksek kalite istediğinde ücretli bir modele uzan.</li>\n<li><strong>Komuttan önce eklentileri ekle</strong> — 3D maketlere veya cihaz çerçevelerine ihtiyacın olacağını biliyorsan.</li>\n<li><strong>Değişiklik için doğru aracı kullan</strong> — öğe editörü ve yorumlar, tam bir yeniden inşa olmadan küçük ince ayarları halleder.</li>\n<li><strong>İşe yarayan düzenleri şablon olarak kaydet</strong> ki bir sonraki projen önden başlasın.</li>\n</ul>\n<h2 id=\"faq\">Sık sorulan sorular</h2>\n<p><strong>Open Design ücretsiz mi?</strong>\nEvet — Apache-2.0 altında açık kaynaktır ve yerelde ücretsiz çalışır. Yalnızca bağladığın ajanın ve medya sağlayıcıların model/API kullanımı için ödeme yaparsın ve Gemini’ninki gibi ücretsiz kademeleri kullanabilirsin.</p>\n<p><strong>Hangi kodlama ajanlarını destekler?</strong>\nClaude Code, Codex CLI, Cursor, Gemini CLI ve OpenCode dahil 21+ ajan. Sağlayıcıyı sağ üstteki menüden seçersin.</p>\n<p><strong>Claude Design’dan farkı nedir?</strong>\nAynı tanıdık his, ama açık kaynaklı, yerel öncelikli ve ajan takılabilir — tek bir modele ya da platforma kilitli değilsin ve projeni istediğin gibi dışa aktarabilir veya dağıtabilirsin.</p>\n<p><strong>Uygulamadan çıkmadan dağıtabilir miyim?</strong>\nEvet — paylaş menüsü tek tıkla Vercel veya Cloudflare’e dağıtır (sağlayıcı erişim token’ını sen verirsin) ya da kodu Cursor’a, VS Code’a veya bir CLI ajanına devreder.</p>\n<p><strong>İyi sonuçlar için ücretli bir model kullanmak zorunda mıyım?</strong>\nHayır — çoğu açılış sayfası ve ön yüz tasarımı için ücretsiz modeller zaten yeterince yetenekli; yalnızca daha ileri sonuçlar istediğinde ücretli bir modele geç.</p>\n<hr>\n<p><em>Bu yazılı rehber, Code A Program’ın demosuna dayanır. Yukarıdaki tam videoyu izle ve daha fazla uygulamalı AI aracı videosu için <a href=\"https://www.youtube.com/watch?v=2AdKzkQyKkg\">Code A Program’a abone ol</a>.</em></p>",
  },
};
